import React, { useState, useEffect } from 'react';
import { BrowserRouter, Routes, Route, useLocation } from 'react-router-dom';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import { Layout } from './components/Layout';
import { LoginModal } from './components/LoginModal';
import { Dashboard } from './pages/Dashboard';
import { AgentIntake } from './pages/AgentIntake';
import { AgentTracking } from './pages/AgentTracking';
import { AgentDatabase } from './pages/AgentDatabase';
import { CrmTeam } from './pages/CrmTeam';
import { LifeOnly } from './pages/forms/LifeOnly';
import { Field } from './pages/forms/Field';
import { DirectPay } from './pages/forms/DirectPay';
import { Telesales } from './pages/forms/Telesales';
import { HIP } from './pages/forms/HIP';
import { ThankYou } from './pages/ThankYou';
import { AgencyPortal } from './pages/AgencyPortal';
import { supabase } from './lib/supabase';
import { AlertCircle } from 'lucide-react';

const KNOWN_PATHS = new Set([
  '', 'dashboard', 'agent-intake', 'new-hires', 'populate-form', 'populate',
  'agent-tracking', 'agent-database', 'crm-team', 'crm',
]);

const ProtectedApp: React.FC = () => {
  const { isAuthenticated, isLoading } = useAuth();
  const location = useLocation();
  const [portalSlug, setPortalSlug] = useState<string | null>(null);
  const [checkingSlug, setCheckingSlug] = useState(false);
  const [slugChecked, setSlugChecked] = useState(false);

  const pathSegments = location.pathname.replace(/^\//, '').split('/');
  const isSingleSegment = pathSegments.length === 1 && pathSegments[0] !== '';
  const potentialSlug = isSingleSegment ? pathSegments[0] : null;
  const isKnownPath = potentialSlug ? KNOWN_PATHS.has(potentialSlug) : true;

  useEffect(() => {
    if (!potentialSlug || isKnownPath) {
      setPortalSlug(null);
      setSlugChecked(true);
      return;
    }

    let cancelled = false;
    setCheckingSlug(true);
    setSlugChecked(false);

    supabase
      .from('crm_agencies')
      .select('slug')
      .eq('slug', potentialSlug)
      .eq('is_active', true)
      .maybeSingle()
      .then(({ data }) => {
        if (cancelled) return;
        setPortalSlug(data ? data.slug : null);
        setCheckingSlug(false);
        setSlugChecked(true);
      })
      .catch(() => {
        if (cancelled) return;
        setPortalSlug(null);
        setCheckingSlug(false);
        setSlugChecked(true);
      });

    return () => { cancelled = true; };
  }, [potentialSlug, isKnownPath]);

  if (potentialSlug && !isKnownPath && (!slugChecked || checkingSlug)) {
    return (
      <div className="flex items-center justify-center h-screen bg-steel-50">
        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-navy-600" />
      </div>
    );
  }

  if (portalSlug) {
    return <AgencyPortal />;
  }

  if (potentialSlug && !isKnownPath && slugChecked && !portalSlug) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl shadow-lg border border-gray-200 p-10 w-full max-w-md text-center">
          <div className="w-16 h-16 rounded-full bg-red-50 flex items-center justify-center mx-auto mb-5">
            <AlertCircle className="w-8 h-8 text-red-400" />
          </div>
          <h2 className="text-2xl font-bold text-gray-900 mb-2">Portal Not Found</h2>
          <p className="text-gray-500 text-sm mb-6">
            The agency portal you're looking for doesn't exist or is no longer active.
          </p>
          <p className="text-xs text-gray-400">
            If you believe this is an error, contact your administrator or email Contracting@teamFYM.com
          </p>
        </div>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-screen bg-steel-50">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-navy-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading...</p>
        </div>
      </div>
    );
  }

  if (!isAuthenticated) {
    return <LoginModal />;
  }

  return (
    <Routes>
      <Route path="/" element={<Layout />}>
        <Route index element={<Dashboard />} />
        <Route path="dashboard" element={<Dashboard />} />
        <Route path="agent-intake" element={<AgentIntake />} />
        <Route path="new-hires" element={<AgentIntake />} />
        <Route path="populate-form" element={<AgentIntake />} />
        <Route path="populate" element={<AgentIntake />} />
        <Route path="agent-tracking" element={<AgentTracking />} />
        <Route path="agent-database" element={<AgentDatabase />} />
        <Route path="crm-team" element={<CrmTeam />} />
        <Route path="crm" element={<CrmTeam />} />
      </Route>
    </Routes>
  );
};

function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          <Route path="/life" element={<LifeOnly />} />
          <Route path="/field" element={<Field />} />
          <Route path="/direct-pay" element={<DirectPay />} />
          <Route path="/telesales" element={<Telesales />} />
          <Route path="/hip" element={<HIP />} />
          <Route path="/hip-career" element={<HIP />} />
          <Route path="/hip-broker" element={<HIP />} />
          <Route path="/field-hip" element={<HIP />} />
          <Route path="/direct-pay-hip" element={<HIP />} />
          <Route path="/telesales-hip" element={<HIP />} />
          <Route path="/thank-you" element={<ThankYou />} />
          <Route path="/*" element={<ProtectedApp />} />
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );
}

export default App;

src/components/AddAgencyModal.tsx:
import React, { useState, useEffect } from 'react';
import { X, Link2 } from 'lucide-react';
import { supabase, generateSlug, RESERVED_SLUGS } from '../lib/supabase';
import type { CrmAgency } from '../lib/supabase';

interface AddAgencyModalProps {
  onClose: () => void;
  onSuccess: () => void;
}

export const AddAgencyModal: React.FC<AddAgencyModalProps> = ({ onClose, onSuccess }) => {
  const [name, setName] = useState('');
  const [dateCreated, setDateCreated] = useState(new Date().toISOString().slice(0, 10));
  const [agencyType, setAgencyType] = useState<'main' | 'sub'>('main');
  const [parentAgencyId, setParentAgencyId] = useState('');
  const [existingAgency, setExistingAgency] = useState(false);
  const [mainAgencies, setMainAgencies] = useState<CrmAgency[]>([]);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    const loadMainAgencies = async () => {
      const { data } = await supabase
        .from('crm_agencies')
        .select('*')
        .eq('agency_type', 'main')
        .eq('is_active', true)
        .order('name');
      setMainAgencies(data || []);
    };
    loadMainAgencies();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSubmitting(true);

    const trimmedName = name.trim();
    if (!trimmedName) {
      setError('Agency name is required.');
      setSubmitting(false);
      return;
    }

    if (agencyType === 'sub' && !parentAgencyId) {
      setError('Please select a parent agency for sub-agencies.');
      setSubmitting(false);
      return;
    }

    const slug = generateSlug(trimmedName);
    if (RESERVED_SLUGS.has(slug)) {
      setError(`The name "${trimmedName}" conflicts with a reserved URL path. Please choose a different name.`);
      setSubmitting(false);
      return;
    }

    const portalPassword = `${trimmedName}CRMPortal!`;

    const { data: newAgency, error: insertError } = await supabase
      .from('crm_agencies')
      .insert({
        name: trimmedName,
        onboarding_status: existingAgency ? 'onboarding_complete' : 'pending_csr_assignment',
        is_active: true,
        agency_type: agencyType,
        parent_agency_id: agencyType === 'sub' ? parentAgencyId : null,
        slug,
        portal_password: portalPassword,
        date_created: dateCreated || null,
        zaps_paused: existingAgency,
      })
      .select()
      .maybeSingle();

    if (insertError) {
      if (insertError.code === '23505') {
        setError('An agency with this name already exists.');
      } else {
        setError('Failed to create agency. Please try again.');
      }
      setSubmitting(false);
      return;
    }

    if (newAgency) {
      const parentName = agencyType === 'sub'
        ? mainAgencies.find((a) => a.id === parentAgencyId)?.name
        : null;
      const message = existingAgency
        ? `Existing agency "${trimmedName}" added -- zaps paused for backfill`
        : agencyType === 'sub'
          ? `New sub-agency "${trimmedName}" added under ${parentName} -- begin onboarding`
          : `New agency "${trimmedName}" added -- begin onboarding`;

      await supabase.from('crm_notifications').insert({
        agency_id: newAgency.id,
        type: 'agency_added',
        message,
      });
    }

    setSubmitting(false);
    onSuccess();
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-xl shadow-xl max-w-md w-full">
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-200">
          <h2 className="text-lg font-bold text-navy-600">Add New Agency</h2>
          <button onClick={onClose} className="p-1 hover:bg-gray-100 rounded transition-colors">
            <X className="w-5 h-5 text-gray-400" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="px-6 py-5 space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Agency Name</label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm"
              placeholder="Enter agency name"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Date Created</label>
            <input
              type="date"
              value={dateCreated}
              onChange={(e) => setDateCreated(e.target.value)}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm"
            />
            <p className="text-xs text-gray-400 mt-1">Backdate if the account was created before today.</p>
          </div>

          <label className="flex items-center gap-2.5 cursor-pointer group">
            <input
              type="checkbox"
              checked={existingAgency}
              onChange={(e) => setExistingAgency(e.target.checked)}
              className="w-4 h-4 rounded border-gray-300 text-navy-600 focus:ring-navy-500"
            />
            <span className="text-sm text-gray-700 group-hover:text-gray-900 transition-colors">
              Existing agency (pause zaps during backfill)
            </span>
          </label>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Agency Type</label>
            <div className="flex rounded-lg border border-gray-300 overflow-hidden">
              <button
                type="button"
                onClick={() => { setAgencyType('main'); setParentAgencyId(''); }}
                className={`flex-1 px-4 py-2.5 text-sm font-medium transition-colors ${
                  agencyType === 'main'
                    ? 'bg-navy-600 text-white'
                    : 'bg-white text-gray-600 hover:bg-gray-50'
                }`}
              >
                Main Agency
              </button>
              <button
                type="button"
                onClick={() => setAgencyType('sub')}
                className={`flex-1 px-4 py-2.5 text-sm font-medium transition-colors border-l border-gray-300 ${
                  agencyType === 'sub'
                    ? 'bg-navy-600 text-white'
                    : 'bg-white text-gray-600 hover:bg-gray-50'
                }`}
              >
                Sub Agency
              </button>
            </div>
          </div>

          {agencyType === 'sub' && (
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Parent Agency</label>
              <select
                value={parentAgencyId}
                onChange={(e) => setParentAgencyId(e.target.value)}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm bg-white"
              >
                <option value="">Select a parent agency...</option>
                {mainAgencies.map((a) => (
                  <option key={a.id} value={a.id}>{a.name}</option>
                ))}
              </select>
              {mainAgencies.length === 0 && (
                <p className="text-xs text-amber-600 mt-1">No active main agencies found. Create a main agency first.</p>
              )}
            </div>
          )}

          {name.trim() && (
            <div className="bg-gray-50 rounded-lg border border-gray-200 p-3 space-y-1">
              <div className="flex items-center gap-2 text-xs">
                <Link2 className="w-3.5 h-3.5 text-gray-400" />
                <span className="text-gray-500">Portal URL:</span>
                <span className="font-mono font-medium text-navy-600">/{generateSlug(name.trim())}</span>
              </div>
              <div className="flex items-center gap-2 text-xs">
                <span className="text-gray-500 ml-5.5">Password:</span>
                <span className="font-mono font-medium text-gray-700">{name.trim()}CRMPortal!</span>
              </div>
            </div>
          )}

          <p className="text-xs text-gray-400">
            {existingAgency
              ? 'The agency will skip onboarding and zaps will be paused until you manually enable them after backfilling data.'
              : agencyType === 'sub'
                ? 'The sub-agency will have its own independent CSR assignment and onboarding workflow.'
                : 'The agency will start in the onboarding workflow where you can assign a CSR, upload rosters, and complete setup.'}
          </p>

          {error && (
            <p className="text-sm text-red-600 bg-red-50 border border-red-200 rounded-lg px-3 py-2">{error}</p>
          )}

          <div className="flex justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              disabled={submitting}
              className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={submitting}
              className="px-4 py-2 text-sm font-medium text-white bg-navy-600 rounded-lg hover:bg-navy-700 transition-colors disabled:opacity-50"
            >
              {submitting ? 'Creating...' : 'Create Agency'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

src/components/AgencyRosterCard.tsx:
import React, { useRef } from 'react';
import { Upload, FileSpreadsheet, Eye, RefreshCw, Trash2 } from 'lucide-react';

type RosterUpload = {
  id: string;
  file_name: string;
  row_count: number;
  headers: string[];
  uploaded_at: string;
  agency: string;
};

interface AgencyRosterCardProps {
  agency: string;
  upload: RosterUpload | null;
  uploading: boolean;
  populatedCount?: number;
  onUpload: (agency: string, file: File) => void;
  onView: (upload: RosterUpload) => void;
  onDelete: (upload: RosterUpload) => void;
}

const DEFAULT_CONFIG = {
  label: 'CRM Roster',
  accent: 'text-gray-700',
  bg: 'bg-gray-50',
  border: 'border-gray-200',
  icon: 'bg-gray-600',
};

const AGENCY_CONFIG: Record<string, { label: string; accent: string; bg: string; border: string; icon: string }> = {
  FYM: {
    label: 'FYM CRM Roster',
    accent: 'text-navy-600',
    bg: 'bg-blue-50',
    border: 'border-blue-200',
    icon: 'bg-navy-600',
  },
  Wisechoice: {
    label: 'Wisechoice CRM Roster',
    accent: 'text-emerald-700',
    bg: 'bg-emerald-50',
    border: 'border-emerald-200',
    icon: 'bg-emerald-600',
  },
  Aspire: {
    label: 'Aspire CRM Roster',
    accent: 'text-amber-700',
    bg: 'bg-amber-50',
    border: 'border-amber-200',
    icon: 'bg-amber-600',
  },
};

export const AgencyRosterCard: React.FC<AgencyRosterCardProps> = ({
  agency,
  upload,
  uploading,
  populatedCount,
  onUpload,
  onView,
  onDelete,
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const config = AGENCY_CONFIG[agency] || { ...DEFAULT_CONFIG, label: `${agency} CRM Roster` };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    onUpload(agency, file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const formatDate = (dateStr: string) => {
    return new Date(dateStr).toLocaleDateString('en-US', {
      month: 'short',
      day: 'numeric',
      year: 'numeric',
      hour: 'numeric',
      minute: '2-digit',
    });
  };

  return (
    <div className={`bg-white rounded-xl shadow-sm border ${config.border} overflow-hidden transition-shadow hover:shadow-md`}>
      <div className={`${config.bg} px-5 py-4 border-b ${config.border}`}>
        <div className="flex items-center gap-3">
          <div className={`${config.icon} w-9 h-9 rounded-lg flex items-center justify-center`}>
            <FileSpreadsheet className="w-5 h-5 text-white" />
          </div>
          <h3 className={`text-lg font-bold ${config.accent}`}>{config.label}</h3>
        </div>
      </div>

      <input
        ref={fileInputRef}
        type="file"
        accept=".csv"
        onChange={handleFileChange}
        className="hidden"
      />

      {upload ? (
        <div className="p-5">
          <div className="flex items-start gap-3 mb-4">
            <div className="min-w-0 flex-1">
              <p className="text-sm font-semibold text-gray-900 truncate" title={upload.file_name}>
                {upload.file_name}
              </p>
              <p className="text-xs text-gray-500 mt-1">
                {populatedCount !== undefined
                  ? `${populatedCount.toLocaleString()}/200 records`
                  : `${upload.row_count.toLocaleString()} records`}
              </p>
              <p className="text-xs text-gray-400 mt-0.5">
                Uploaded {formatDate(upload.uploaded_at)}
              </p>
            </div>
          </div>

          <div className="flex flex-col gap-2">
            <button
              onClick={() => onView(upload)}
              className={`flex items-center justify-center gap-2 w-full px-4 py-2.5 ${config.icon} text-white rounded-lg hover:opacity-90 transition-all font-medium text-sm`}
            >
              <Eye className="w-4 h-4" />
              View Roster
            </button>
            <div className="flex gap-2">
              <button
                onClick={() => fileInputRef.current?.click()}
                disabled={uploading}
                className="flex items-center justify-center gap-2 flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition-colors text-sm font-medium disabled:opacity-50"
              >
                <RefreshCw className="w-3.5 h-3.5" />
                Replace
              </button>
              <button
                onClick={() => onDelete(upload)}
                className="flex items-center justify-center gap-2 px-4 py-2 border border-red-200 text-red-600 rounded-lg hover:bg-red-50 transition-colors text-sm font-medium"
              >
                <Trash2 className="w-3.5 h-3.5" />
              </button>
            </div>
          </div>
        </div>
      ) : (
        <div className="p-5">
          <div className="flex flex-col items-center text-center py-4">
            <div className="w-12 h-12 rounded-full bg-gray-100 flex items-center justify-center mb-3">
              <Upload className="w-5 h-5 text-gray-400" />
            </div>
            <p className="text-sm text-gray-500 mb-4">No roster uploaded</p>
            <button
              onClick={() => fileInputRef.current?.click()}
              disabled={uploading}
              className={`flex items-center gap-2 px-5 py-2.5 ${config.icon} text-white rounded-lg hover:opacity-90 transition-all font-medium text-sm disabled:opacity-50`}
            >
              <Upload className="w-4 h-4" />
              {uploading ? 'Uploading...' : 'Upload CSV'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

