import React, { useState } from 'react';
import {
  Plus,
  Search,
  TrendingUp,
  DollarSign,
  Target,
  Percent,
  X,
  Briefcase,
} from 'lucide-react';
import { supabase } from '../../lib/supabase';
import type { AgencyDeal } from '../../lib/supabase';

interface AgencyDealsTabProps {
  agencyId: string;
  deals: AgencyDeal[];
  onDealsUpdated: (deals: AgencyDeal[]) => void;
}

const STATUS_COLORS: Record<string, string> = {
  open: 'bg-blue-100 text-blue-800',
  won: 'bg-emerald-100 text-emerald-800',
  lost: 'bg-red-100 text-red-800',
  abandoned: 'bg-gray-100 text-gray-600',
};

export const AgencyDealsTab: React.FC<AgencyDealsTabProps> = ({ agencyId, deals, onDealsUpdated }) => {
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [showAddModal, setShowAddModal] = useState(false);

  const filtered = deals.filter((d) => {
    if (statusFilter !== 'all' && d.status !== statusFilter) return false;
    if (search) {
      const q = search.toLowerCase();
      return (
        d.deal_name.toLowerCase().includes(q) ||
        (d.contact_name || '').toLowerCase().includes(q) ||
        (d.assigned_agent_name || '').toLowerCase().includes(q)
      );
    }
    return true;
  });

  const wonDeals = deals.filter((d) => d.status === 'won');
  const lostDeals = deals.filter((d) => d.status === 'lost');
  const openDeals = deals.filter((d) => d.status === 'open');
  const totalRevenue = wonDeals.reduce((s, d) => s + (d.value || 0), 0);
  const winRate = wonDeals.length + lostDeals.length > 0
    ? Math.round((wonDeals.length / (wonDeals.length + lostDeals.length)) * 100)
    : 0;

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <SummaryCard icon={Briefcase} label="Total Deals" value={deals.length.toString()} color="text-navy-600" bg="bg-blue-50" />
        <SummaryCard icon={DollarSign} label="Revenue" value={`$${totalRevenue.toLocaleString()}`} color="text-emerald-600" bg="bg-emerald-50" />
        <SummaryCard icon={Target} label="Won / Lost" value={`${wonDeals.length} / ${lostDeals.length}`} color="text-amber-600" bg="bg-amber-50" />
        <SummaryCard icon={Percent} label="Win Rate" value={`${winRate}%`} color="text-teal-600" bg="bg-teal-50" />
      </div>

      <div className="flex items-center gap-3">
        <div className="relative flex-1 max-w-sm">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input
            type="text"
            placeholder="Search deals..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm"
          />
        </div>
        <div className="flex items-center gap-1 bg-white border border-gray-200 rounded-lg p-1">
          {['all', 'open', 'won', 'lost', 'abandoned'].map((s) => (
            <button
              key={s}
              onClick={() => setStatusFilter(s)}
              className={`px-3 py-1.5 text-xs font-medium rounded-md transition-colors capitalize ${
                statusFilter === s ? 'bg-navy-600 text-white' : 'text-gray-600 hover:bg-gray-100'
              }`}
            >
              {s}
            </button>
          ))}
        </div>
        <button
          onClick={() => setShowAddModal(true)}
          className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-white bg-navy-600 rounded-lg hover:bg-navy-700 transition-colors ml-auto"
        >
          <Plus className="w-4 h-4" />
          Add Deal
        </button>
      </div>

      <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Deal Name</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Contact</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase">Value</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Stage</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Agent</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Close Date</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {filtered.map((deal) => (
                <tr key={deal.id} className="hover:bg-gray-50 transition-colors">
                  <td className="px-6 py-3 whitespace-nowrap text-sm font-medium text-gray-900">{deal.deal_name}</td>
                  <td className="px-6 py-3 whitespace-nowrap text-sm text-gray-600">{deal.contact_name || '--'}</td>
                  <td className="px-6 py-3 whitespace-nowrap text-sm font-medium text-gray-900 text-right">
                    ${(deal.value || 0).toLocaleString()}
                  </td>
                  <td className="px-6 py-3 whitespace-nowrap text-sm text-gray-600">{deal.stage || '--'}</td>
                  <td className="px-6 py-3 whitespace-nowrap">
                    <span className={`inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium capitalize ${STATUS_COLORS[deal.status] || 'bg-gray-100 text-gray-600'}`}>
                      {deal.status}
                    </span>
                  </td>
                  <td className="px-6 py-3 whitespace-nowrap text-sm text-gray-600">{deal.assigned_agent_name || '--'}</td>
                  <td className="px-6 py-3 whitespace-nowrap text-sm text-gray-600">
                    {deal.close_date ? new Date(deal.close_date).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) : '--'}
                  </td>
                </tr>
              ))}
              {filtered.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center">
                    <TrendingUp className="w-8 h-8 text-gray-300 mx-auto mb-2" />
                    <p className="text-sm text-gray-500">
                      {deals.length === 0 ? 'No deals yet. Connect GHL or add deals manually.' : 'No deals match your filters.'}
                    </p>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showAddModal && (
        <AddDealModal
          agencyId={agencyId}
          onClose={() => setShowAddModal(false)}
          onDealAdded={(deal) => {
            onDealsUpdated([...deals, deal]);
            setShowAddModal(false);
          }}
        />
      )}
    </div>
  );
};

const SummaryCard: React.FC<{
  icon: React.FC<{ className?: string }>;
  label: string;
  value: string;
  color: string;
  bg: string;
}> = ({ icon: Icon, label, value, color, bg }) => (
  <div className="bg-white rounded-xl border border-gray-200 p-4">
    <div className={`w-8 h-8 rounded-lg ${bg} flex items-center justify-center mb-2`}>
      <Icon className={`w-4 h-4 ${color}`} />
    </div>
    <p className={`text-xl font-bold ${color}`}>{value}</p>
    <p className="text-xs text-gray-500 mt-0.5">{label}</p>
  </div>
);

const AddDealModal: React.FC<{
  agencyId: string;
  onClose: () => void;
  onDealAdded: (deal: AgencyDeal) => void;
}> = ({ agencyId, onClose, onDealAdded }) => {
  const [form, setForm] = useState({
    deal_name: '',
    contact_name: '',
    value: '',
    stage: '',
    status: 'open',
    assigned_agent_name: '',
  });
  const [saving, setSaving] = useState(false);

  const handleSave = async () => {
    if (!form.deal_name.trim()) return;
    setSaving(true);

    const { data, error } = await supabase
      .from('agency_deals')
      .insert({
        agency_id: agencyId,
        deal_name: form.deal_name.trim(),
        contact_name: form.contact_name.trim() || null,
        value: parseFloat(form.value) || 0,
        stage: form.stage.trim() || 'New',
        status: form.status,
        assigned_agent_name: form.assigned_agent_name.trim() || null,
      })
      .select()
      .maybeSingle();

    if (!error && data) {
      onDealAdded(data);
    }
    setSaving(false);
  };

  const inputClass = 'w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm';

  return (
    <div className="fixed inset-0 bg-black/40 z-50 flex items-center justify-center p-4" onClick={onClose}>
      <div className="bg-white rounded-xl shadow-xl w-full max-w-lg" onClick={(e) => e.stopPropagation()}>
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-200">
          <h3 className="font-semibold text-gray-900">Add Deal</h3>
          <button onClick={onClose} className="p-1 rounded-lg hover:bg-gray-100 transition-colors">
            <X className="w-5 h-5 text-gray-400" />
          </button>
        </div>

        <div className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Deal Name *</label>
            <input type="text" value={form.deal_name} onChange={(e) => setForm({ ...form, deal_name: e.target.value })} className={inputClass} placeholder="Deal name" />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Contact Name</label>
              <input type="text" value={form.contact_name} onChange={(e) => setForm({ ...form, contact_name: e.target.value })} className={inputClass} placeholder="Contact" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Value ($)</label>
              <input type="number" value={form.value} onChange={(e) => setForm({ ...form, value: e.target.value })} className={inputClass} placeholder="0" />
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Stage</label>
              <input type="text" value={form.stage} onChange={(e) => setForm({ ...form, stage: e.target.value })} className={inputClass} placeholder="e.g. New, Qualified" />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
              <select value={form.status} onChange={(e) => setForm({ ...form, status: e.target.value })} className={inputClass}>
                <option value="open">Open</option>
                <option value="won">Won</option>
                <option value="lost">Lost</option>
                <option value="abandoned">Abandoned</option>
              </select>
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Assigned Agent</label>
            <input type="text" value={form.assigned_agent_name} onChange={(e) => setForm({ ...form, assigned_agent_name: e.target.value })} className={inputClass} placeholder="Agent name" />
          </div>
        </div>

        <div className="flex items-center justify-end gap-3 px-6 py-4 border-t border-gray-200">
          <button onClick={onClose} className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors">
            Cancel
          </button>
          <button
            onClick={handleSave}
            disabled={saving || !form.deal_name.trim()}
            className="px-5 py-2 text-sm font-medium text-white bg-navy-600 rounded-lg hover:bg-navy-700 transition-colors disabled:opacity-50"
          >
            {saving ? 'Adding...' : 'Add Deal'}
          </button>
        </div>
      </div>
    </div>
  );
};

src/pages/crm/AgencyGhlTab.tsx:
import React, { useState } from 'react';
import {
  Link2,
  Wifi,
  WifiOff,
  AlertTriangle,
  RefreshCw,
  Eye,
  EyeOff,
  CheckCircle2,
  Clock,
} from 'lucide-react';
import { supabase } from '../../lib/supabase';
import type { AgencyGhlConfig } from '../../lib/supabase';

interface AgencyGhlTabProps {
  agencyId: string;
  config: AgencyGhlConfig | null;
  onConfigUpdated: (config: AgencyGhlConfig | null) => void;
}

const STATUS_DISPLAY: Record<string, { label: string; icon: React.FC<{ className?: string }>; color: string; bg: string }> = {
  connected: { label: 'Connected', icon: Wifi, color: 'text-emerald-700', bg: 'bg-emerald-50 border-emerald-200' },
  error: { label: 'Error', icon: AlertTriangle, color: 'text-red-700', bg: 'bg-red-50 border-red-200' },
  disconnected: { label: 'Disconnected', icon: WifiOff, color: 'text-gray-500', bg: 'bg-gray-50 border-gray-200' },
};

export const AgencyGhlTab: React.FC<AgencyGhlTabProps> = ({ agencyId, config, onConfigUpdated }) => {
  const [apiKey, setApiKey] = useState(config?.ghl_api_key || '');
  const [locationId, setLocationId] = useState(config?.ghl_location_id || '');
  const [showKey, setShowKey] = useState(false);
  const [saving, setSaving] = useState(false);
  const [testing, setTesting] = useState(false);
  const [syncing, setSyncing] = useState(false);
  const [syncProgress, setSyncProgress] = useState<{ fetched: number; total: number } | null>(null);
  const [testResult, setTestResult] = useState<{ ok: boolean; message: string } | null>(null);

  const maskedKey = apiKey ? `${'*'.repeat(Math.max(0, apiKey.length - 4))}${apiKey.slice(-4)}` : '';

  const handleSave = async () => {
    setSaving(true);
    setTestResult(null);

    if (config) {
      const { data, error } = await supabase
        .from('agency_ghl_configs')
        .update({
          ghl_api_key: apiKey.trim(),
          ghl_location_id: locationId.trim(),
          updated_at: new Date().toISOString(),
        })
        .eq('id', config.id)
        .select()
        .maybeSingle();

      if (!error && data) onConfigUpdated(data);
    } else {
      const { data, error } = await supabase
        .from('agency_ghl_configs')
        .insert({
          agency_id: agencyId,
          ghl_api_key: apiKey.trim(),
          ghl_location_id: locationId.trim(),
          connection_status: 'disconnected',
        })
        .select()
        .maybeSingle();

      if (!error && data) onConfigUpdated(data);
    }

    setSaving(false);
  };

  const handleTestConnection = async () => {
    setTesting(true);
    setTestResult(null);

    try {
      const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
      const supabaseKey = import.meta.env.VITE_SUPABASE_ANON_KEY;

      const res = await fetch(`${supabaseUrl}/functions/v1/sync-ghl-data`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${supabaseKey}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ agency_id: agencyId, test_only: true }),
      });

      const result = await res.json();

      if (res.ok && result.success) {
        setTestResult({ ok: true, message: 'Connection successful' });

        if (config) {
          const { data } = await supabase
            .from('agency_ghl_configs')
            .update({ connection_status: 'connected', last_error: null, updated_at: new Date().toISOString() })
            .eq('id', config.id)
            .select()
            .maybeSingle();
          if (data) onConfigUpdated(data);
        }
      } else {
        setTestResult({ ok: false, message: result.error || 'Connection failed' });

        if (config) {
          const { data } = await supabase
            .from('agency_ghl_configs')
            .update({ connection_status: 'error', last_error: result.error || 'Test failed', updated_at: new Date().toISOString() })
            .eq('id', config.id)
            .select()
            .maybeSingle();
          if (data) onConfigUpdated(data);
        }
      }
    } catch {
      setTestResult({ ok: false, message: 'Failed to reach sync endpoint. Make sure the edge function is deployed.' });
    }

    setTesting(false);
  };

  const handleSync = async () => {
    setSyncing(true);
    setSyncProgress(null);

    try {
      const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
      const supabaseKey = import.meta.env.VITE_SUPABASE_ANON_KEY;
      const headers = {
        'Authorization': `Bearer ${supabaseKey}`,
        'Content-Type': 'application/json',
      };

      let complete = false;
      let isFirst = true;

      while (!complete) {
        const res = await fetch(`${supabaseUrl}/functions/v1/sync-ghl-data`, {
          method: 'POST',
          headers,
          body: JSON.stringify({ agency_id: agencyId, reset_sync: isFirst }),
        });
        isFirst = false;

        if (!res.ok) break;
        const result = await res.json();
        if (!result.success) break;

        setSyncProgress({
          fetched: result.fetched_so_far || 0,
          total: result.total_expected || 0,
        });

        complete = result.complete;
        if (!complete) {
          await new Promise(r => setTimeout(r, 2000));
        }
      }

      const { data } = await supabase
        .from('agency_ghl_configs')
        .select('*')
        .eq('agency_id', agencyId)
        .maybeSingle();
      if (data) onConfigUpdated(data);
    } catch {
      // sync failed silently
    }

    setSyncing(false);
    setSyncProgress(null);
  };

  const status = config?.connection_status || 'disconnected';
  const statusInfo = STATUS_DISPLAY[status] || STATUS_DISPLAY.disconnected;
  const StatusIcon = statusInfo.icon;

  return (
    <div className="space-y-6">
      <div className={`rounded-xl border p-5 ${statusInfo.bg}`}>
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <StatusIcon className={`w-5 h-5 ${statusInfo.color}`} />
            <div>
              <p className={`text-sm font-semibold ${statusInfo.color}`}>GHL {statusInfo.label}</p>
              {config?.last_sync_at && (
                <p className="text-xs text-gray-500 mt-0.5">
                  Last sync: {new Date(config.last_sync_at).toLocaleString()}
                </p>
              )}
              {config?.connection_status === 'connected' && (
                <p className="text-xs text-gray-400 mt-0.5">
                  Auto-syncs daily at 9am, 12pm, and 6pm EST
                </p>
              )}
            </div>
          </div>
          {config?.connection_status === 'connected' && (
            <button
              onClick={handleSync}
              disabled={syncing}
              className="flex items-center gap-2 px-3 py-1.5 text-xs font-medium text-navy-600 bg-white border border-navy-600/20 rounded-lg hover:bg-navy-50 transition-colors disabled:opacity-50"
            >
              <RefreshCw className={`w-3.5 h-3.5 ${syncing ? 'animate-spin' : ''}`} />
              {syncing
                ? syncProgress
                  ? `${syncProgress.fetched.toLocaleString()}${syncProgress.total ? ` / ${syncProgress.total.toLocaleString()}` : ''}`
                  : 'Starting...'
                : 'Sync Now'}
            </button>
          )}
        </div>
        {config?.last_error && status === 'error' && (
          <div className="mt-3 p-3 bg-red-100/50 rounded-lg">
            <p className="text-xs text-red-700">{config.last_error}</p>
          </div>
        )}
      </div>

      <div className="bg-white rounded-xl border border-gray-200 p-6">
        <div className="flex items-center gap-3 mb-5">
          <div className="w-9 h-9 rounded-lg bg-blue-50 flex items-center justify-center">
            <Link2 className="w-5 h-5 text-navy-600" />
          </div>
          <div>
            <h3 className="font-semibold text-gray-900">GHL API Credentials</h3>
            <p className="text-xs text-gray-500">Connect this agency to GoHighLevel</p>
          </div>
        </div>

        <div className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">API Key</label>
            <div className="relative">
              <input
                type={showKey ? 'text' : 'password'}
                value={apiKey}
                onChange={(e) => setApiKey(e.target.value)}
                placeholder="Enter GHL API key"
                className="w-full px-4 py-2.5 pr-10 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm font-mono"
              />
              <button
                type="button"
                onClick={() => setShowKey(!showKey)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
              >
                {showKey ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
            {apiKey && !showKey && (
              <p className="mt-1 text-xs text-gray-400 font-mono">{maskedKey}</p>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Location ID</label>
            <input
              type="text"
              value={locationId}
              onChange={(e) => setLocationId(e.target.value)}
              placeholder="Enter GHL Location ID"
              className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm font-mono"
            />
          </div>

          <div className="flex items-center gap-3 pt-2">
            <button
              onClick={handleSave}
              disabled={saving || !apiKey.trim() || !locationId.trim()}
              className="px-5 py-2 text-sm font-medium text-white bg-navy-600 rounded-lg hover:bg-navy-700 transition-colors disabled:opacity-50"
            >
              {saving ? 'Saving...' : 'Save Credentials'}
            </button>
            <button
              onClick={handleTestConnection}
              disabled={testing || !config}
              className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-navy-600 bg-blue-50 border border-navy-600/20 rounded-lg hover:bg-blue-100 transition-colors disabled:opacity-50"
            >
              {testing ? (
                <>
                  <RefreshCw className="w-4 h-4 animate-spin" />
                  Testing...
                </>
              ) : (
                <>
                  <Wifi className="w-4 h-4" />
                  Test Connection
                </>
              )}
            </button>
          </div>

          {testResult && (
            <div className={`flex items-center gap-2 p-3 rounded-lg ${testResult.ok ? 'bg-emerald-50 text-emerald-700' : 'bg-red-50 text-red-700'}`}>
              {testResult.ok ? <CheckCircle2 className="w-4 h-4" /> : <AlertTriangle className="w-4 h-4" />}
              <p className="text-sm">{testResult.message}</p>
            </div>
          )}
        </div>
      </div>

      <div className="bg-white rounded-xl border border-gray-200 p-6">
        <h3 className="text-sm font-semibold text-gray-700 mb-3">How it works</h3>
        <div className="space-y-3">
          <StepInfo step={1} text="Enter your GHL API key and Location ID above" />
          <StepInfo step={2} text="Click 'Test Connection' to verify the credentials work" />
          <StepInfo step={3} text="Once connected, click 'Sync Now' to pull deal data from GHL" />
          <StepInfo step={4} text="Deal data will appear in the Deals tab and on the Dashboard" />
        </div>
      </div>
    </div>
  );
};

const StepInfo: React.FC<{ step: number; text: string }> = ({ step, text }) => (
  <div className="flex items-start gap-3">
    <div className="w-6 h-6 rounded-full bg-gray-100 flex items-center justify-center flex-shrink-0 mt-0.5">
      <span className="text-xs font-bold text-gray-500">{step}</span>
    </div>
    <p className="text-sm text-gray-600">{text}</p>
  </div>
);

