        <h3 className="text-sm font-semibold text-gray-700">Agency Portal</h3>
      </div>
      <div className="space-y-3">
        <DetailRow label="Portal URL">
          <span className="text-sm font-mono font-medium text-navy-600">{portalUrl}</span>
