import React, { useState, useEffect } from 'react';
import {
  FileSpreadsheet,
  ChevronLeft,
  ChevronRight,
  ArrowLeft,
  Search,
  Undo2,
  Download,
  UserX,
  Zap,
} from 'lucide-react';
import { supabase } from '../../lib/supabase';
import { parseCSV } from '../../lib/csvParser';
import { fireCrmOnboardingWebhook, warmUpCrmOnboardingWebhook } from '../../lib/webhooks';
import { AgencyRosterCard } from '../../components/AgencyRosterCard';
import { normalizeRosterRows } from '../../lib/rosterNormalizer';

const MALE_PROFILE_IMAGE = 'https://storage.googleapis.com/msgsndr/YM9XmCanfO6p28b1sQOH/media/6882b3d23303840127a970fb.png';
const FEMALE_PROFILE_IMAGE = 'https://storage.googleapis.com/msgsndr/YM9XmCanfO6p28b1sQOH/media/6882b3d2f665866357dfd218.png';

type RosterUpload = {
  id: string;
  file_name: string;
  row_count: number;
  headers: string[];
  uploaded_at: string;
  agency: string;
};

type RosterRow = {
  id: string;
  upload_id: string;
  row_data: Record<string, string>;
  created_at: string;
};

const PAGE_SIZE = 50;

export const RosterTab: React.FC = () => {
  const [agencyNames, setAgencyNames] = useState<string[]>([]);
  const [agencyFilter, setAgencyFilter] = useState('All');
  const [uploadsByAgency, setUploadsByAgency] = useState<Record<string, RosterUpload | null>>({});
  const [activeUpload, setActiveUpload] = useState<RosterUpload | null>(null);
  const [allRows, setAllRows] = useState<RosterRow[]>([]);
  const [page, setPage] = useState(0);
  const [loading, setLoading] = useState(true);
  const [uploadingAgency, setUploadingAgency] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [deleteConfirm, setDeleteConfirm] = useState<RosterUpload | null>(null);
  const [deleting, setDeleting] = useState(false);
  const [undoConfirmRow, setUndoConfirmRow] = useState<RosterRow | null>(null);
  const [undoSubmitting, setUndoSubmitting] = useState(false);
  const [undoError, setUndoError] = useState('');
  const [terminateRow, setTerminateRow] = useState<RosterRow | null>(null);
  const [terminateSubmitting, setTerminateSubmitting] = useState(false);
  const [terminateError, setTerminateError] = useState('');
  const [populatedCounts, setPopulatedCounts] = useState<Record<string, number>>({});

  useEffect(() => {
    loadUploads();
  }, []);

  useEffect(() => {
    if (activeUpload) {
      loadRows();
    }
  }, [activeUpload]);

  const loadUploads = async () => {
    setLoading(true);
    const [uploadsRes, agencyRes] = await Promise.all([
      supabase.from('crm_roster_uploads').select('*').order('uploaded_at', { ascending: false }),
      supabase.from('crm_agencies').select('name').eq('is_active', true).order('name'),
    ]);

    const names = (agencyRes.data || []).map((a: { name: string }) => a.name);
    setAgencyNames(names);

    const byAgency: Record<string, RosterUpload | null> = {};
    for (const name of names) {
      byAgency[name] = null;
    }

    if (uploadsRes.data) {
      for (const upload of uploadsRes.data) {
        if (upload.agency && byAgency.hasOwnProperty(upload.agency)) {
          byAgency[upload.agency] = upload;
        }
      }
    }

    setUploadsByAgency(byAgency);
    setLoading(false);

    const uploadIds = Object.values(byAgency)
      .filter((u): u is RosterUpload => u !== null)
      .map((u) => u.id);

    if (uploadIds.length > 0) {
      const { data: rosterRows } = await supabase
        .from('crm_roster')
        .select('upload_id, row_data')
        .in('upload_id', uploadIds);

      if (rosterRows) {
        const counts: Record<string, number> = {};
        for (const name of names) {
          const upload = byAgency[name];
          if (!upload) continue;
          counts[name] = rosterRows.filter(
            (r) =>
              r.upload_id === upload.id &&
              r.row_data['First Name']?.trim()
          ).length;
        }
        setPopulatedCounts(counts);
      }
    }
  };

  const loadRows = async () => {
    if (!activeUpload) return;

    const { data } = await supabase
      .from('crm_roster')
      .select('*')
      .eq('upload_id', activeUpload.id);

    const sorted = (data || []).sort((a, b) => {
      const aNum = parseInt(a.row_data['Seat Number'] || '', 10);
      const bNum = parseInt(b.row_data['Seat Number'] || '', 10);
      if (isNaN(aNum) && isNaN(bNum)) return 0;
      if (isNaN(aNum)) return 1;
      if (isNaN(bNum)) return -1;
      return aNum - bNum;
    });
    setAllRows(sorted);
  };

  const padRosterTo200 = async (uploadId: string, headers: string[]) => {
    const { data: existingRows } = await supabase
      .from('crm_roster')
      .select('id, row_data')
      .eq('upload_id', uploadId);

    const numericRows = (existingRows || []).filter(
      (r) => /^\d+$/.test(r.row_data['Seat Number'] || '')
    );

    const occupiedSeats = new Set(numericRows.map((r) => Number(r.row_data['Seat Number'])));

    let crmNumber = '';
    const rowWithCrm = numericRows.find((r) => r.row_data['All Templates | Agent CRM #']?.trim());
    if (rowWithCrm) {
      crmNumber = rowWithCrm.row_data['All Templates | Agent CRM #'];
    }

    const emptyRow = (seat: number): Record<string, string> => {
      const row: Record<string, string> = {};
      for (const h of headers) {
        row[h] = '';
      }
      row['Seat Number'] = String(seat);
      if (crmNumber) {
        row['All Templates | Agent CRM #'] = crmNumber;
      }
      return row;
    };

    const rowsToInsert: { upload_id: string; row_data: Record<string, string> }[] = [];
    for (let seat = 1; seat <= 200; seat++) {
      if (!occupiedSeats.has(seat)) {
        rowsToInsert.push({ upload_id: uploadId, row_data: emptyRow(seat) });
      }
    }

    if (crmNumber) {
      const rowsMissingCrm = numericRows.filter(
        (r) => !r.row_data['All Templates | Agent CRM #']?.trim()
      );
      for (const row of rowsMissingCrm) {
        await supabase
          .from('crm_roster')
          .update({ row_data: { ...row.row_data, 'All Templates | Agent CRM #': crmNumber } })
          .eq('id', row.id);
      }
    }

    const BATCH_SIZE = 500;
    for (let i = 0; i < rowsToInsert.length; i += BATCH_SIZE) {
      const batch = rowsToInsert.slice(i, i + BATCH_SIZE);
      await supabase.from('crm_roster').insert(batch);
    }
  };

  const handleUpload = async (agency: string, file: File) => {
    setUploadingAgency(agency);

    try {
      const text = await file.text();
      const { rows: rawRows } = parseCSV(text);

      if (rawRows.length === 0) {
        alert('CSV file appears to be empty or invalid.');
        setUploadingAgency(null);
        return;
      }

      const { data: agencyRecord } = await supabase
        .from('crm_agencies')
        .select('crm_number')
        .eq('name', agency)
        .maybeSingle();
      const crmNumber = agencyRecord?.crm_number || '';

      const { headers: canonicalHeaders, rows: normalizedRows } = normalizeRosterRows(rawRows, crmNumber);

      const existing = uploadsByAgency[agency];
      if (existing) {
        await supabase.from('crm_roster_uploads').delete().eq('id', existing.id);
      }

      const { data: uploadRecord, error: uploadError } = await supabase
        .from('crm_roster_uploads')
        .insert({
          file_name: file.name,
          row_count: normalizedRows.length,
          headers: canonicalHeaders,
          agency,
        })
        .select()
        .maybeSingle();

      if (uploadError || !uploadRecord) {
        throw uploadError || new Error('Failed to create upload record');
      }

      const BATCH_SIZE = 500;
      for (let i = 0; i < normalizedRows.length; i += BATCH_SIZE) {
        const batch = normalizedRows.slice(i, i + BATCH_SIZE).map((row) => ({
          upload_id: uploadRecord.id,
          row_data: row,
        }));

        const { error: insertError } = await supabase.from('crm_roster').insert(batch);
        if (insertError) throw insertError;
      }

      await padRosterTo200(uploadRecord.id, canonicalHeaders);
      await loadUploads();
    } catch (err) {
      console.error(err);
      alert('Error uploading CSV. Please check the file and try again.');
    } finally {
      setUploadingAgency(null);
    }
  };

  const handleView = (upload: RosterUpload) => {
    setActiveUpload(upload);
    setPage(0);
    setSearchTerm('');
    setAllRows([]);
  };

  const handleDelete = async () => {
    if (!deleteConfirm) return;
    setDeleting(true);

    const { error } = await supabase
      .from('crm_roster_uploads')
      .delete()
      .eq('id', deleteConfirm.id);

    if (!error) {
      if (activeUpload?.id === deleteConfirm.id) {
        setActiveUpload(null);
        setAllRows([]);
      }
      await loadUploads();
    }

    setDeleting(false);
    setDeleteConfirm(null);
  };

  const handleBack = () => {
    setActiveUpload(null);
    setAllRows([]);
    setSearchTerm('');
    setPage(0);
  };

  const handleRosterUndo = async () => {
    if (!undoConfirmRow || !activeUpload) return;
    setUndoSubmitting(true);
    setUndoError('');

    try {
      const clearedRowData = {
        ...undoConfirmRow.row_data,
        'First Name': '',
        'Last Name': '',
        'Phone': '',
        'Email': '',
        'Agent NPN': '',
        'All Templates | Agent Profile Image': '',
      };

      const { error: updateError } = await supabase
        .from('crm_roster')
        .update({ row_data: clearedRowData })
        .eq('id', undoConfirmRow.id);

      if (updateError) {
        setUndoError('Failed to clear roster seat. Please try again.');
        setUndoSubmitting(false);
        return;
      }

      const agency = activeUpload.agency;
      const { data: matchingAgents } = await supabase
        .from('agents')
        .select('id, first_name, last_name')
        .eq('status', 'completed')
        .eq('agency', agency);

      const testerAgents = (matchingAgents || []).filter(
        (a) => a.first_name.toLowerCase() === 'tester' && a.last_name.toLowerCase() === 'mitchell'
      );

      for (const agent of testerAgents) {
        await supabase
          .from('agents')
          .update({ crm_onboarded: false })
          .eq('id', agent.id);
      }

      await loadRows();
      setUndoSubmitting(false);
      setUndoConfirmRow(null);
    } catch {
      setUndoError('An unexpected error occurred. Please try again.');
      setUndoSubmitting(false);
    }
  };

  const handleRosterTerminate = async () => {
    if (!terminateRow || !activeUpload) return;
    setTerminateSubmitting(true);
    setTerminateError('');

    try {
      const firstName = terminateRow.row_data['First Name'] || '';
      const lastName = terminateRow.row_data['Last Name'] || '';
      const email = terminateRow.row_data['Email'] || '';
      const agency = activeUpload.agency;

      const { data: agencyData } = await supabase
        .from('crm_agencies')
        .select('csr_can_fill_seat, csr_first_name, csr_last_name, csr_phone, csr_email, csr_npn, csr_gender, zaps_paused')
        .eq('name', agency)
        .maybeSingle();

      const csrCanFill = agencyData?.csr_can_fill_seat && agencyData?.csr_npn?.trim();

      if (csrCanFill) {
        const csrProfileImage = agencyData.csr_gender === 'Male' ? MALE_PROFILE_IMAGE : agencyData.csr_gender === 'Female' ? FEMALE_PROFILE_IMAGE : '';
        const csrRowData = {
          ...terminateRow.row_data,
          'First Name': agencyData.csr_first_name || '',
          'Last Name': agencyData.csr_last_name || '',
          'Phone': agencyData.csr_phone || '',
          'Email': agencyData.csr_email || '',
          'Agent NPN': agencyData.csr_npn || '',
          'All Templates | Agent Profile Image': csrProfileImage,
          'CSR Placeholder': 'true',
        };

        const { error: updateError } = await supabase
          .from('crm_roster')
          .update({ row_data: csrRowData })
          .eq('id', terminateRow.id);

        if (updateError) {
          setTerminateError('Failed to update roster seat with CSR. Please try again.');
          setTerminateSubmitting(false);
          return;
        }

        if (!agencyData.zaps_paused) {
          const crmNumber = terminateRow.row_data['All Templates | Agent CRM #'] || '';
          await fireCrmOnboardingWebhook({
            seatNumber: terminateRow.row_data['Seat Number'] || '',
            agentNpn: agencyData.csr_npn || '',
            firstName: agencyData.csr_first_name || '',
            lastName: agencyData.csr_last_name || '',
            email: agencyData.csr_email || '',
            phone: agencyData.csr_phone || '',
            profileImage: csrProfileImage,
            crmNumber,
            agency,
          });
        }
      } else {
        const clearedRowData = {
          ...terminateRow.row_data,
          'First Name': '',
          'Last Name': '',
          'Phone': '',
          'Email': '',
          'Agent NPN': '',
          'All Templates | Agent Profile Image': '',
          'CSR Placeholder': '',
        };

        const { error: updateError } = await supabase
          .from('crm_roster')
          .update({ row_data: clearedRowData })
          .eq('id', terminateRow.id);

        if (updateError) {
          setTerminateError('Failed to clear roster seat. Please try again.');
          setTerminateSubmitting(false);
          return;
        }
      }

      const now = new Date().toISOString();

      const { data: matchingAgents } = await supabase
        .from('agents')
        .select('id')
        .eq('status', 'completed')
        .eq('agency', agency)
        .ilike('first_name', firstName)
        .ilike('last_name', lastName)
        .ilike('email', email);

      if (matchingAgents && matchingAgents.length > 0) {
        for (const agent of matchingAgents) {
          await supabase
            .from('agents')
            .update({ status: 'terminated', crm_onboarded: false, terminated_at: now, updated_at: now })
            .eq('id', agent.id);

          await supabase
            .from('crm_pipeline')
            .update({ terminated_at: now, updated_at: now })
            .eq('agent_id', agent.id);
        }
      }

      await loadRows();
      setTerminateSubmitting(false);
      setTerminateRow(null);
    } catch {
      setTerminateError('An unexpected error occurred. Please try again.');
      setTerminateSubmitting(false);
    }
  };

  const filteredRows = searchTerm
    ? allRows.filter((row) =>
        Object.values(row.row_data).some((val) =>
          String(val).toLowerCase().includes(searchTerm.toLowerCase())
        )
      )
    : allRows;

  const totalRows = filteredRows.length;
  const totalPages = Math.ceil(totalRows / PAGE_SIZE);
  const paginatedRows = filteredRows.slice(page * PAGE_SIZE, (page + 1) * PAGE_SIZE);

  const visibleAgencies = agencyFilter === 'All'
    ? agencyNames
    : agencyNames.filter((a) => a === agencyFilter);

  if (loading) {
    return (
      <div className="space-y-4">
        <div className="flex items-center gap-2 bg-white border border-steel-200 rounded-xl p-1.5">
          {[...Array(4)].map((_, i) => <div key={i} className="h-8 w-24 bg-steel-100 rounded-lg animate-pulse" />)}
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {[...Array(6)].map((_, i) => <div key={i} className="h-36 bg-white rounded-2xl border border-steel-200 animate-pulse" />)}
        </div>
      </div>
    );
  }

  return (
    <>
      {!activeUpload && (
        <div className="flex items-center gap-2 mb-5">
          {['All', ...agencyNames].map((a) => (
            <button
              key={a}
              onClick={() => setAgencyFilter(a)}
              className={`px-3 py-1.5 text-sm font-medium rounded-lg transition-colors ${
                agencyFilter === a
                  ? 'bg-navy-600 text-white'
                  : 'bg-white text-gray-600 border border-gray-300 hover:bg-gray-50'
              }`}
            >
              {a}
            </button>
          ))}
        </div>
      )}

      {!activeUpload ? (
        <div className={`grid gap-6 ${visibleAgencies.length === 1 ? 'grid-cols-1 max-w-md' : 'grid-cols-1 md:grid-cols-3'}`}>
          {visibleAgencies.map((agency) => (
            <AgencyRosterCard
              key={agency}
              agency={agency}
              upload={uploadsByAgency[agency]}
              uploading={uploadingAgency === agency}
              populatedCount={populatedCounts[agency]}
              onUpload={handleUpload}
              onView={handleView}
              onDelete={setDeleteConfirm}
            />
          ))}
        </div>
      ) : (
        <RosterTableView
          upload={activeUpload}
          rows={paginatedRows}
          allRows={allRows}
          totalRows={totalRows}
          totalPages={totalPages}
          page={page}
          searchTerm={searchTerm}
          onSearchChange={setSearchTerm}
          onPageChange={setPage}
          onBack={handleBack}
          onUndo={(row) => { setUndoError(''); setUndoConfirmRow(row); }}
          onTerminate={(row) => { setTerminateError(''); setTerminateRow(row); }}
        />
      )}

      {deleteConfirm && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-xl max-w-md w-full animate-in fade-in">
            <div className="px-6 py-4 border-b border-gray-200">
              <h2 className="text-lg font-bold text-red-600">Delete Upload</h2>
            </div>
            <div className="px-6 py-5">
              <p className="text-gray-700">
                This will permanently delete{' '}
                <span className="font-semibold">{deleteConfirm.file_name}</span> and all{' '}
                <span className="font-semibold">{deleteConfirm.row_count.toLocaleString()}</span>{' '}
                associated records for{' '}
                <span className="font-semibold">{deleteConfirm.agency}</span>.
              </p>
              <p className="text-gray-500 text-sm mt-2">This action cannot be undone.</p>
            </div>
            <div className="px-6 py-4 bg-gray-50 rounded-b-xl flex justify-end gap-3">
              <button
                onClick={() => setDeleteConfirm(null)}
                disabled={deleting}
                className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleDelete}
                disabled={deleting}
                className="px-4 py-2 text-sm font-medium text-white bg-red-600 rounded-lg hover:bg-red-700 transition-colors disabled:opacity-50"
              >
                {deleting ? 'Deleting...' : 'Delete'}
              </button>
            </div>
          </div>
        </div>
      )}
      {undoConfirmRow && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-xl max-w-md w-full animate-in fade-in">
            <div className="px-6 py-4 border-b border-gray-200">
              <h2 className="text-lg font-bold text-orange-600">Undo CRM Seat</h2>
            </div>
            <div className="px-6 py-5">
              <p className="text-gray-700">
                This will clear the agent data from seat <span className="font-semibold">#{undoConfirmRow.row_data['Seat Number']}</span> for{' '}
                <span className="font-semibold">{undoConfirmRow.row_data['First Name']} {undoConfirmRow.row_data['Last Name']}</span> and
                allow re-onboarding.
              </p>
              <p className="text-gray-500 text-sm mt-2">This is a test-only action.</p>
              {undoError && (
                <p className="mt-3 text-sm text-red-600 bg-red-50 border border-red-200 rounded-md px-3 py-2">{undoError}</p>
              )}
            </div>
            <div className="px-6 py-4 bg-gray-50 rounded-b-xl flex justify-end gap-3">
              <button
                onClick={() => { setUndoConfirmRow(null); setUndoError(''); }}
                disabled={undoSubmitting}
                className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleRosterUndo}
                disabled={undoSubmitting}
                className="px-4 py-2 text-sm font-medium text-white bg-orange-500 rounded-lg hover:bg-orange-600 transition-colors disabled:opacity-50"
              >
                {undoSubmitting ? 'Clearing...' : 'Confirm'}
              </button>
            </div>
          </div>
        </div>
      )}

      {terminateRow && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-xl max-w-md w-full animate-in fade-in">
            <div className="px-6 py-4 border-b border-gray-200">
              <h2 className="text-lg font-bold text-red-600">Terminate Agent</h2>
            </div>
            <div className="px-6 py-5">
              <p className="text-gray-700">
                This will terminate <span className="font-semibold">{terminateRow.row_data['First Name']} {terminateRow.row_data['Last Name']}</span>,
                clear seat <span className="font-semibold">#{terminateRow.row_data['Seat Number']}</span> from the{' '}
                <span className="font-semibold">{activeUpload?.agency}</span> CRM roster,
                and mark them as terminated.
              </p>
              <p className="text-gray-500 text-sm mt-2">This action cannot be undone.</p>
              {terminateError && (
                <p className="mt-3 text-sm text-red-600 bg-red-50 border border-red-200 rounded-md px-3 py-2">{terminateError}</p>
              )}
            </div>
            <div className="px-6 py-4 bg-gray-50 rounded-b-xl flex justify-end gap-3">
              <button
                onClick={() => { setTerminateRow(null); setTerminateError(''); }}
                disabled={terminateSubmitting}
                className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleRosterTerminate}
                disabled={terminateSubmitting}
                className="px-4 py-2 text-sm font-medium text-white bg-red-600 rounded-lg hover:bg-red-700 transition-colors disabled:opacity-50"
              >
                {terminateSubmitting ? 'Terminating...' : 'Terminate'}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

interface RosterTableViewProps {
  upload: RosterUpload;
  rows: RosterRow[];
  allRows: RosterRow[];
  totalRows: number;
  totalPages: number;
  page: number;
  searchTerm: string;
  onSearchChange: (term: string) => void;
  onPageChange: (page: number) => void;
  onBack: () => void;
  onUndo: (row: RosterRow) => void;
  onTerminate: (row: RosterRow) => void;
}

const escapeCSVField = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`;
  }
  return value;
};

const RosterTableView: React.FC<RosterTableViewProps> = ({
  upload,
  rows,
  allRows,
  totalRows,
  totalPages,
  page,
  searchTerm,
  onSearchChange,
  onPageChange,
  onBack,
  onUndo,
  onTerminate,
}) => {
  const [zapConfirmOpen, setZapConfirmOpen] = useState(false);
  const [zapSending, setZapSending] = useState(false);
  const [zapProgress, setZapProgress] = useState({ sent: 0, total: 0, failed: 0 });
  const [zapResult, setZapResult] = useState<{ sent: number; failed: number; total: number } | null>(null);

  const AGENCY_COLORS: Record<string, string> = {
    FYM: 'text-navy-600',
    Wisechoice: 'text-emerald-700',
    Aspire: 'text-amber-700',
  };

  const populatedRows = allRows.filter((row) => row.row_data['First Name']?.trim());

  const handleFireToZap = async () => {
    setZapConfirmOpen(false);
    setZapSending(true);
    setZapResult(null);

    const { data: agencyData } = await supabase
      .from('crm_agencies')
      .select('zaps_paused')
      .eq('name', upload.agency)
      .maybeSingle();

    if (agencyData?.zaps_paused) {
      setZapSending(false);
      setZapResult({ sent: 0, failed: 0, total: populatedRows.length });
      return;
    }

    const total = populatedRows.length;
    setZapProgress({ sent: 0, total, failed: 0 });

    // Warm up the edge function to eliminate cold start issues
    await warmUpCrmOnboardingWebhook();
    await new Promise((r) => setTimeout(r, 1500));

    let sent = 0;
    let failed = 0;
    const failedRows: typeof populatedRows = [];

    for (const row of populatedRows) {
      const success = await fireCrmOnboardingWebhook({
        seatNumber: row.row_data['Seat Number'] || '',
        agentNpn: row.row_data['Agent NPN'] || '',
        firstName: row.row_data['First Name'] || '',
        lastName: row.row_data['Last Name'] || '',
        email: row.row_data['Email'] || '',
        phone: row.row_data['Phone'] || '',
        profileImage: row.row_data['All Templates | Agent Profile Image'] || '',
        crmNumber: row.row_data['All Templates | Agent CRM #'] || '',
        agency: upload.agency,
      });

      if (success) {
        sent++;
      } else {
        failed++;
        failedRows.push(row);
      }
      setZapProgress({ sent, total, failed });

      await new Promise((r) => setTimeout(r, 3000));
    }

    // Retry failed rows once with a longer delay
    if (failedRows.length > 0) {
      await new Promise((r) => setTimeout(r, 5000));
      for (const row of failedRows) {
        const success = await fireCrmOnboardingWebhook({
          seatNumber: row.row_data['Seat Number'] || '',
          agentNpn: row.row_data['Agent NPN'] || '',
          firstName: row.row_data['First Name'] || '',
          lastName: row.row_data['Last Name'] || '',
          email: row.row_data['Email'] || '',
          phone: row.row_data['Phone'] || '',
          profileImage: row.row_data['All Templates | Agent Profile Image'] || '',
          crmNumber: row.row_data['All Templates | Agent CRM #'] || '',
          agency: upload.agency,
        });

        if (success) {
          sent++;
          failed--;
          setZapProgress({ sent, total, failed });
        }

        await new Promise((r) => setTimeout(r, 5000));
      }
    }

    setZapSending(false);
    setZapResult({ sent, failed, total });
  };

  const handleExport = () => {
    const headers = upload.headers;
    const csvHeader = headers.map(escapeCSVField).join(',');
    const csvRows = allRows.map((row) =>
      headers.map((h) => escapeCSVField(row.row_data[h] || '')).join(',')
    );
    const csvContent = [csvHeader, ...csvRows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${upload.agency}_roster_export.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  return (
    <>
      <div className="mb-6 flex items-center justify-between">
        <div className="flex items-center gap-4">
          <button
            onClick={onBack}
            className="flex items-center gap-2 px-3 py-2 text-sm font-medium text-gray-600 hover:text-gray-900 hover:bg-gray-100 rounded-lg transition-colors"
          >
            <ArrowLeft className="w-4 h-4" />
            Back
          </button>
          <div className="flex items-center gap-3">
            <FileSpreadsheet className="w-6 h-6 text-gray-400" />
            <div>
              <h2 className={`text-xl font-bold ${AGENCY_COLORS[upload.agency] || 'text-gray-900'}`}>
                {upload.agency} CRM Roster
              </h2>

              <p className="text-sm text-gray-500">
                {upload.file_name} -- {totalRows.toLocaleString()} records
              </p>
            </div>
          </div>
        </div>
        <div className="flex items-center gap-3">
          <button
            onClick={() => { setZapResult(null); setZapConfirmOpen(true); }}
            disabled={zapSending || populatedRows.length === 0}
            className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-white bg-amber-500 rounded-lg hover:bg-amber-600 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
          >
            <Zap className="w-4 h-4" />
            {zapSending
              ? `Sending ${zapProgress.sent}/${zapProgress.total}...`
              : `Send to Zap (${populatedRows.length})`}
          </button>
          <button
            onClick={handleExport}
            disabled={allRows.length === 0}
            className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-white bg-navy-600 rounded-lg hover:bg-navy-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
          >
            <Download className="w-4 h-4" />
            Export CSV
          </button>
        </div>
      </div>

      {zapSending && zapProgress.total > 0 && (
        <div className="mb-4">
          <div className="flex items-center justify-between text-sm text-gray-600 mb-1.5">
            <span>Sending {zapProgress.sent + zapProgress.failed} of {zapProgress.total}...</span>
            <span className="tabular-nums font-medium">
              {Math.round(((zapProgress.sent + zapProgress.failed) / zapProgress.total) * 100)}%
            </span>
          </div>
          <div className="w-full h-3 bg-gray-200 rounded-full overflow-hidden">
            <div
              className="h-full rounded-full transition-all duration-500 ease-out"
              style={{
                width: `${((zapProgress.sent + zapProgress.failed) / zapProgress.total) * 100}%`,
                background: zapProgress.failed > 0
                  ? 'linear-gradient(90deg, #f59e0b, #ef4444)'
                  : 'linear-gradient(90deg, #f59e0b, #22c55e)',
              }}
            />
          </div>
          <div className="flex items-center gap-4 mt-1.5 text-xs text-gray-500">
            <span className="text-green-600 font-medium">{zapProgress.sent} sent</span>
            {zapProgress.failed > 0 && (
              <span className="text-red-600 font-medium">{zapProgress.failed} failed</span>
            )}
          </div>
        </div>
      )}

      {zapResult && (
        <div className={`mb-4 px-4 py-3 rounded-lg text-sm font-medium ${
          zapResult.failed === 0 && zapResult.sent > 0
            ? 'bg-green-50 text-green-700 border border-green-200'
            : zapResult.sent === 0
            ? 'bg-red-50 text-red-700 border border-red-200'
            : 'bg-amber-50 text-amber-700 border border-amber-200'
        }`}>
          {zapResult.sent === 0 && zapResult.failed === 0
            ? 'Zaps are paused for this agency. No rows were sent.'
            : `Sent ${zapResult.sent} of ${zapResult.total} agents to Zap.${zapResult.failed > 0 ? ` ${zapResult.failed} failed.` : ''}`}
          <button onClick={() => setZapResult(null)} className="ml-3 underline opacity-70 hover:opacity-100">Dismiss</button>
        </div>
      )}

      {zapConfirmOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-xl max-w-md w-full animate-in fade-in">
            <div className="px-6 py-4 border-b border-gray-200">
              <h2 className="text-lg font-bold text-amber-600">Send Roster to Zap</h2>
            </div>
            <div className="px-6 py-5">
              <p className="text-gray-700">
                This will send <span className="font-semibold">{populatedRows.length}</span> populated agent rows
                to the onboarding Zap for <span className="font-semibold">{upload.agency}</span>, one at a time.
              </p>
              <p className="text-gray-500 text-sm mt-2">Each row includes: Seat Number, First Name, Last Name, Email, Phone, Agent NPN, Profile Image, and CRM Number.</p>
            </div>
            <div className="px-6 py-4 bg-gray-50 rounded-b-xl flex justify-end gap-3">
              <button
                onClick={() => setZapConfirmOpen(false)}
                className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleFireToZap}
                className="px-4 py-2 text-sm font-medium text-white bg-amber-500 rounded-lg hover:bg-amber-600 transition-colors"
              >
                Send All
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-4 mb-4">
        <div className="flex items-center justify-between gap-4">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
            <input
              type="text"
              placeholder="Search across all columns..."
              value={searchTerm}
              onChange={(e) => onSearchChange(e.target.value)}
              className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm"
            />
          </div>
          <p className="text-sm text-gray-500 whitespace-nowrap">
            {totalRows.toLocaleString()} total records
          </p>
        </div>
      </div>

      <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase whitespace-nowrap">
                  #
                </th>
                {upload.headers.map((header) => (
                  <th
                    key={header}
                    className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase whitespace-nowrap"
                  >
                    {header}
                  </th>
                ))}
                <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase whitespace-nowrap">
                  Actions
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {rows.length === 0 ? (
                <tr>
                  <td
                    colSpan={upload.headers.length + 2}
                    className="px-4 py-8 text-center text-gray-500"
                  >
                    {searchTerm ? 'No matching records found.' : 'No data available.'}
                  </td>
                </tr>
              ) : (
                rows.map((row, idx) => (
                  <tr key={row.id} className={`transition-colors ${row.row_data['CSR Placeholder'] === 'true' ? 'bg-amber-50 hover:bg-amber-100' : 'hover:bg-gray-50'}`}>
                    <td className="px-4 py-3 text-sm text-gray-400 whitespace-nowrap">
                      {page * PAGE_SIZE + idx + 1}
                    </td>
                    {upload.headers.map((header) => (
                      <td
                        key={header}
                        className="px-4 py-3 text-sm text-gray-900 whitespace-nowrap max-w-[250px] truncate"
                        title={row.row_data[header] || ''}
                      >
                        {header === 'First Name' && row.row_data['CSR Placeholder'] === 'true' ? (
                          <span className="flex items-center gap-1.5">
                            {row.row_data[header] || ''}
                            <span className="inline-flex items-center px-1.5 py-0.5 text-[10px] font-semibold uppercase tracking-wide bg-amber-200 text-amber-800 rounded">
                              CSR
                            </span>
                          </span>
                        ) : (
                          row.row_data[header] || ''
                        )}
                      </td>
                    ))}
                    <td className="px-4 py-3 text-sm whitespace-nowrap">
                      <div className="flex items-center gap-1">
                        {row.row_data['First Name']?.toLowerCase() === 'tester' &&
                         row.row_data['Last Name']?.toLowerCase() === 'mitchell' && (
                          <div className="relative group/undo">
                            <button
                              onClick={() => onUndo(row)}
                              className="p-1.5 text-orange-500 hover:bg-orange-50 rounded transition-colors"
                              aria-label="Undo CRM seat"
                            >
                              <Undo2 className="w-4 h-4" />
                            </button>
                            <span className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-2.5 py-1 text-xs font-medium text-white bg-gray-800 rounded whitespace-nowrap opacity-0 group-hover/undo:opacity-100 transition-opacity pointer-events-none">
                              Undo CRM (Test Only)
                              <span className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-gray-800" />
                            </span>
                          </div>
                        )}
                        {row.row_data['First Name']?.trim() && (
                          <div className="relative group/terminate">
                            <button
                              onClick={() => onTerminate(row)}
                              className="p-1.5 text-red-500 hover:bg-red-50 rounded transition-colors"
                              aria-label="Terminate agent"
                            >
                              <UserX className="w-4 h-4" />
                            </button>
                            <span className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 px-2.5 py-1 text-xs font-medium text-white bg-gray-800 rounded whitespace-nowrap opacity-0 group-hover/terminate:opacity-100 transition-opacity pointer-events-none">
                              Terminate Agent
                              <span className="absolute top-full left-1/2 -translate-x-1/2 border-4 border-transparent border-t-gray-800" />
                            </span>
                          </div>
                        )}
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {totalPages > 1 && (
          <div className="flex items-center justify-between px-4 py-3 border-t border-gray-200 bg-gray-50">
            <p className="text-sm text-gray-600">
              Page {page + 1} of {totalPages}
            </p>
            <div className="flex items-center gap-2">
              <button
                onClick={() => onPageChange(Math.max(0, page - 1))}
                disabled={page === 0}
                className="flex items-center gap-1 px-3 py-1.5 text-sm border border-gray-300 rounded-lg hover:bg-gray-100 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
              >
                <ChevronLeft className="w-4 h-4" />
                Previous
              </button>
              <button
                onClick={() => onPageChange(Math.min(totalPages - 1, page + 1))}
                disabled={page >= totalPages - 1}
                className="flex items-center gap-1 px-3 py-1.5 text-sm border border-gray-300 rounded-lg hover:bg-gray-100 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
              >
                Next
                <ChevronRight className="w-4 h-4" />
              </button>
            </div>
          </div>
        )}
      </div>
    </>
  );
};

src/pages/crm/TaskboardCurrentTab.tsx:
import React, { useState, useEffect, useCallback } from 'react';
import {
  AlertCircle,
  Loader2,
  CheckCircle2,
  Clock,
  Building2,
  Send,
  ChevronDown,
  Tag,
  User,
  ArrowLeft,
  MessageSquareText,
  FileText,
  ChevronRight,
  XCircle,
  FileDown,
} from 'lucide-react';
import { supabase } from '../../lib/supabase';
import type { CrmTicket, CrmTicketMessage } from '../../lib/supabase';

interface TicketWithAgency extends CrmTicket {
  agency_name: string;
}

interface PendingCancellationUpload {
  id: string;
  agency_id: string;
  agency_name: string;
  file_name: string;
  row_count: number;
  created_at: string;
}

interface CancellationRow {
  first_name: string;
  last_name: string;
  phone: string;
  tag: string;
}


const STATUS_COLUMNS: { key: CrmTicket['status']; label: string; color: string; headerBg: string; icon: React.FC<{ className?: string }> }[] = [
  { key: 'open', label: 'Open', color: 'border-blue-200', headerBg: 'bg-blue-50', icon: AlertCircle },
  { key: 'in-progress', label: 'In Progress', color: 'border-amber-200', headerBg: 'bg-amber-50', icon: Loader2 },
  { key: 'resolved', label: 'Resolved', color: 'border-emerald-200', headerBg: 'bg-emerald-50', icon: CheckCircle2 },
];

const PRIORITY_CONFIG: Record<string, { label: string; dot: string }> = {
  low: { label: 'Low', dot: 'bg-gray-400' },
  normal: { label: 'Normal', dot: 'bg-blue-500' },
  high: { label: 'High', dot: 'bg-red-500' },
};

const CATEGORY_LABELS: Record<string, string> = {
  'agent-issue': 'Agent Issue',
  'crm-issue': 'CRM Issue',
  billing: 'Billing',
  other: 'Other',
};

function timeAgo(dateStr: string): string {
  const diff = Date.now() - new Date(dateStr).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return 'Just now';
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  const days = Math.floor(hrs / 24);
  if (days < 7) return `${days}d ago`;
  return new Date(dateStr).toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
}

export const TaskboardCurrentTab: React.FC = () => {
  const [tickets, setTickets] = useState<TicketWithAgency[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedTicket, setSelectedTicket] = useState<TicketWithAgency | null>(null);

  const loadTickets = useCallback(async () => {
    const { data } = await supabase
      .from('crm_tickets')
      .select('*, crm_agencies!inner(name)')
      .in('status', ['open', 'in-progress', 'resolved'])
      .order('created_at', { ascending: false });

    const mapped: TicketWithAgency[] = (data || []).map((row: any) => ({
      ...row,
      agency_name: row.crm_agencies?.name || 'Unknown',
      crm_agencies: undefined,
    }));
    setTickets(mapped);
    setLoading(false);
  }, []);

  useEffect(() => { loadTickets(); }, [loadTickets]);

  const handleStatusChange = async (ticketId: string, newStatus: CrmTicket['status']) => {
    const updates: Record<string, unknown> = { status: newStatus, updated_at: new Date().toISOString() };
    if (newStatus === 'resolved') updates.resolved_at = new Date().toISOString();

    await supabase.from('crm_tickets').update(updates).eq('id', ticketId);
    setTickets(prev => prev.map(t => t.id === ticketId ? { ...t, status: newStatus } : t));
    if (selectedTicket?.id === ticketId) {
      setSelectedTicket(prev => prev ? { ...prev, status: newStatus } : null);
    }
  };

  if (loading) {
    return (
      <div className="space-y-4">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
          {[...Array(3)].map((_, i) => <div key={i} className="h-64 bg-white rounded-2xl border border-steel-200 animate-pulse" />)}
        </div>
      </div>
    );
  }

  if (selectedTicket) {
    return (
      <TicketDetailPanel
        ticket={selectedTicket}
        onBack={() => { setSelectedTicket(null); loadTickets(); }}
        onStatusChange={handleStatusChange}
      />
    );
  }

  return (
    <div className="space-y-4">
      <CancellationApprovalsSection />

      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-lg font-bold text-steel-900">Support Tickets</h2>
          <p className="text-sm text-steel-500">{tickets.length} active ticket{tickets.length !== 1 ? 's' : ''} across all agencies</p>
        </div>
        <button
          onClick={loadTickets}
          className="text-sm text-steel-500 hover:text-steel-700 transition-colors"
        >
          Refresh
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {STATUS_COLUMNS.map(col => {
          const colTickets = tickets.filter(t => t.status === col.key);
          const Icon = col.icon;
          return (
            <div key={col.key} className={`rounded-2xl border ${col.color} bg-white/50 min-h-[400px] shadow-sm`}>
              <div className={`px-4 py-3 border-b ${col.color} flex items-center gap-2 rounded-t-2xl ${col.headerBg}`}>
                <Icon className="w-4 h-4 text-steel-600" />
                <span className="text-sm font-semibold text-steel-800">{col.label}</span>
                <span className="ml-auto text-[11px] font-bold text-steel-600 bg-white/80 px-2 py-0.5 rounded-full shadow-sm">
                  {colTickets.length}
                </span>
              </div>
              <div className="p-3 space-y-3">
                {colTickets.length === 0 && (
                  <p className="text-xs text-steel-400 text-center py-8">No tickets</p>
                )}
                {colTickets.map(ticket => (
                  <TicketCard
                    key={ticket.id}
                    ticket={ticket}
                    onClick={() => setSelectedTicket(ticket)}
                    onStatusChange={handleStatusChange}
                  />
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const CancellationApprovalsSection: React.FC = () => {
  const [pending, setPending] = useState<PendingCancellationUpload[]>([]);
  const [loading, setLoading] = useState(true);
  const [expanded, setExpanded] = useState(true);
  const [previewUploadId, setPreviewUploadId] = useState<string | null>(null);
  const [previewRows, setPreviewRows] = useState<CancellationRow[]>([]);
  const [loadingPreview, setLoadingPreview] = useState(false);
  const [processingId, setProcessingId] = useState<string | null>(null);
  const [rejectingUpload, setRejectingUpload] = useState<PendingCancellationUpload | null>(null);
  const [rejectReason, setRejectReason] = useState('');
  const [submittingReject, setSubmittingReject] = useState(false);

  const loadPending = useCallback(async () => {
    const { data } = await supabase
      .from('agency_cancellation_uploads')
      .select('id, agency_id, file_name, row_count, created_at, crm_agencies!inner(name)')
      .eq('status', 'pending_approval')
      .order('created_at', { ascending: false });

    const mapped: PendingCancellationUpload[] = (data || []).map((row: any) => ({
      id: row.id,
      agency_id: row.agency_id,
      agency_name: row.crm_agencies?.name || 'Unknown',
      file_name: row.file_name,
      row_count: row.row_count,
      created_at: row.created_at,
    }));
    setPending(mapped);
    setLoading(false);
  }, []);

  useEffect(() => { loadPending(); }, [loadPending]);

  const loadPreview = async (uploadId: string) => {
    if (previewUploadId === uploadId) {
      setPreviewUploadId(null);
      return;
    }
    setPreviewUploadId(uploadId);
    setLoadingPreview(true);
    const { data } = await supabase
      .from('agency_cancellations')
      .select('first_name, last_name, phone, tag')
      .eq('upload_id', uploadId)
      .limit(10);
    setPreviewRows((data as CancellationRow[]) || []);
    setLoadingPreview(false);
  };

  const handleConfirm = async (upload: PendingCancellationUpload) => {
    setProcessingId(upload.id);
    const confirmedAt = new Date().toISOString();

    await supabase
      .from('agency_cancellation_uploads')
      .update({ status: 'success', confirmed_at: confirmedAt })
      .eq('id', upload.id);

    const { data: rows } = await supabase
      .from('agency_cancellations')
      .select('first_name, last_name, phone, tag')
      .eq('upload_id', upload.id);

    const csvHeaders = 'First Name,Last Name,Phone,Tag';
    const csvRows = (rows || []).map((r: any) =>
      [r.first_name, r.last_name, r.phone, r.tag]
        .map(v => `"${(v || '').replace(/"/g, '""')}"`)
        .join(',')
    );
    const csvContent = [csvHeaders, ...csvRows].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${upload.agency_name.replace(/\s+/g, '_')}_cancellations_${new Date().toISOString().slice(0, 10)}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);

    await supabase.from('crm_notifications').insert({
      agency_id: upload.agency_id,
      type: 'cancellation_confirmed',
      message: `Cancellation upload "${upload.file_name}" confirmed and processed for ${upload.agency_name}`,
    });

    setProcessingId(null);
    loadPending();
  };

  const handleReject = async () => {
    if (!rejectingUpload || !rejectReason.trim()) return;
    setSubmittingReject(true);

    await supabase
      .from('agency_cancellation_uploads')
      .update({ status: 'rejected', rejection_reason: rejectReason.trim() })
      .eq('id', rejectingUpload.id);

    await supabase.from('crm_notifications').insert({
      agency_id: rejectingUpload.agency_id,
      type: 'cancellation_rejected',
      message: `Cancellation upload "${rejectingUpload.file_name}" rejected: ${rejectReason.trim()}`,
    });

    setSubmittingReject(false);
    setRejectingUpload(null);
    setRejectReason('');
    loadPending();
  };

  if (loading) return null;
  if (pending.length === 0) return null;

  return (
    <div className="mb-6">
      <button
        onClick={() => setExpanded(!expanded)}
        className="flex items-center gap-2 w-full text-left mb-3 group"
      >
        <ChevronRight className={`w-4 h-4 text-steel-500 transition-transform duration-200 ${expanded ? 'rotate-90' : ''}`} />
        <h3 className="text-sm font-bold text-steel-900">Cancellation Uploads Pending Approval</h3>
        <span className="ml-2 px-2.5 py-0.5 text-[11px] font-bold bg-amber-100 text-amber-700 rounded-full">
          {pending.length}
        </span>
      </button>

      {rejectingUpload && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl shadow-xl max-w-md w-full">
            <div className="px-6 py-4 border-b border-gray-200">
              <h2 className="text-lg font-bold text-gray-900">Reject Cancellation Upload</h2>
            </div>
            <div className="px-6 py-5 space-y-4">
              <p className="text-sm text-gray-700">
                This will reject the upload <span className="font-semibold">"{rejectingUpload.file_name}"</span> from{' '}
                <span className="font-semibold">{rejectingUpload.agency_name}</span>. They will see your explanation and can re-upload corrected data.
              </p>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Reason *</label>
                <textarea
                  value={rejectReason}
                  onChange={(e) => setRejectReason(e.target.value)}
                  rows={3}
                  className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-red-500 focus:border-transparent text-sm resize-none"
                  placeholder="Explain why the cancellation upload is being rejected..."
                />
              </div>
            </div>
            <div className="px-6 py-4 bg-gray-50 rounded-b-xl flex justify-end gap-3">
              <button
                onClick={() => { setRejectingUpload(null); setRejectReason(''); }}
                disabled={submittingReject}
                className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleReject}
                disabled={submittingReject || !rejectReason.trim()}
                className="px-4 py-2 text-sm font-medium text-white bg-red-600 rounded-lg hover:bg-red-700 transition-colors disabled:opacity-50"
              >
                {submittingReject ? 'Rejecting...' : 'Reject Upload'}
              </button>
            </div>
          </div>
        </div>
      )}

      {expanded && (
        <div className="space-y-3">
          {pending.map(upload => (
            <div key={upload.id} className="bg-white rounded-xl border border-amber-200 shadow-sm overflow-hidden hover:shadow-md transition-shadow duration-200">
              <div className="px-4 py-3 flex items-center gap-3">
                <FileText className="w-5 h-5 text-amber-600 shrink-0" />
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <span className="text-sm font-semibold text-steel-900 truncate">{upload.file_name}</span>
                    <span className="text-xs text-steel-500">{upload.row_count} rows</span>
                  </div>
                  <div className="flex items-center gap-2 mt-0.5">
                    <Building2 className="w-3 h-3 text-steel-400" />
                    <span className="text-xs text-steel-600">{upload.agency_name}</span>
                    <span className="text-xs text-steel-400">
                      {timeAgo(upload.created_at)}
                    </span>
                  </div>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  <button
                    onClick={() => loadPreview(upload.id)}
                    className="px-2.5 py-1.5 text-xs font-medium text-steel-600 bg-steel-100 rounded-md hover:bg-steel-200 transition-colors"
                  >
                    {previewUploadId === upload.id ? 'Hide' : 'Preview'}
                  </button>
                  <button
                    onClick={() => setRejectingUpload(upload)}
                    disabled={processingId === upload.id}
                    className="px-2.5 py-1.5 text-xs font-medium text-red-700 bg-red-50 border border-red-200 rounded-md hover:bg-red-100 transition-colors disabled:opacity-50"
                  >
                    <XCircle className="w-3.5 h-3.5 inline -mt-0.5 mr-1" />
                    Reject
                  </button>
                  <button
                    onClick={() => handleConfirm(upload)}
                    disabled={processingId === upload.id}
                    className="px-3 py-1.5 text-xs font-medium text-white bg-emerald-600 rounded-md hover:bg-emerald-700 transition-colors disabled:opacity-50"
                  >
                    {processingId === upload.id ? (
                      <Loader2 className="w-3.5 h-3.5 animate-spin inline" />
                    ) : (
                      <>
                        <FileDown className="w-3.5 h-3.5 inline -mt-0.5 mr-1" />
                        Confirm & Download CSV
                      </>
                    )}
                  </button>
                </div>
              </div>

              {previewUploadId === upload.id && (
                <div className="border-t border-amber-100 bg-amber-50/30 px-4 py-3">
                  {loadingPreview ? (
                    <div className="text-center py-3">
                      <Loader2 className="w-4 h-4 animate-spin text-steel-400 mx-auto" />
                    </div>
                  ) : previewRows.length === 0 ? (
                    <p className="text-xs text-steel-500 text-center py-2">No rows found</p>
                  ) : (
                    <table className="w-full text-xs">
                      <thead>
                        <tr className="border-b border-amber-200">
                          <th className="px-2 py-1.5 text-left font-medium text-steel-600">First Name</th>
                          <th className="px-2 py-1.5 text-left font-medium text-steel-600">Last Name</th>
                          <th className="px-2 py-1.5 text-left font-medium text-steel-600">Phone</th>
                          <th className="px-2 py-1.5 text-left font-medium text-steel-600">Tag</th>
                        </tr>
                      </thead>
                      <tbody>
                        {previewRows.map((row, i) => (
                          <tr key={i} className="border-b border-amber-100 last:border-0">
                            <td className="px-2 py-1.5 text-steel-800">{row.first_name}</td>
                            <td className="px-2 py-1.5 text-steel-800">{row.last_name}</td>
                            <td className="px-2 py-1.5 text-steel-800">{row.phone}</td>
                            <td className="px-2 py-1.5 text-steel-700 font-mono">{row.tag}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  )}
                  {previewRows.length > 0 && upload.row_count > 10 && (
                    <p className="text-[10px] text-steel-500 mt-2">Showing 10 of {upload.row_count} rows</p>
                  )}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

const TicketCard: React.FC<{
  ticket: TicketWithAgency;
  onClick: () => void;
  onStatusChange: (id: string, status: CrmTicket['status']) => void;
}> = ({ ticket, onClick, onStatusChange }) => {
  const [showStatusMenu, setShowStatusMenu] = useState(false);
  const priority = PRIORITY_CONFIG[ticket.priority] || PRIORITY_CONFIG.normal;

  return (
    <div
      className="bg-white rounded-xl border border-steel-200 shadow-sm hover:shadow-md hover:border-navy-200 transition-all duration-200 cursor-pointer group"
      onClick={onClick}
    >
      <div className="p-4">
        <div className="flex items-start justify-between gap-2 mb-2.5">
          <h4 className="text-sm font-semibold text-steel-900 line-clamp-2 leading-snug group-hover:text-navy-800 transition-colors">
            {ticket.subject}
          </h4>
          <div className="relative shrink-0" onClick={e => e.stopPropagation()}>
            <button
              onClick={() => setShowStatusMenu(!showStatusMenu)}
              className="p-1.5 rounded-lg hover:bg-steel-100 transition-colors"
            >
              <ChevronDown className="w-3.5 h-3.5 text-steel-400" />
            </button>
            {showStatusMenu && (
              <div className="absolute right-0 top-full mt-1 bg-white border border-steel-200 rounded-xl shadow-xl z-10 min-w-[130px] py-1">
                {(['open', 'in-progress', 'resolved', 'closed'] as CrmTicket['status'][]).map(s => (
                  <button
                    key={s}
                    onClick={() => { onStatusChange(ticket.id, s); setShowStatusMenu(false); }}
                    className={`w-full text-left px-3 py-2 text-xs hover:bg-steel-50 transition-colors ${
                      ticket.status === s ? 'font-semibold text-navy-700' : 'text-steel-700'
                    }`}
                  >
                    {s === 'in-progress' ? 'In Progress' : s.charAt(0).toUpperCase() + s.slice(1)}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>

        <div className="flex items-center gap-1.5 mb-2.5">
          <Building2 className="w-3 h-3 text-navy-400" />
          <span className="text-xs font-medium text-navy-700">{ticket.agency_name}</span>
        </div>

        <div className="flex items-center gap-2 flex-wrap">
          <span className="inline-flex items-center gap-1 text-[10px] font-medium text-steel-700 bg-steel-100 px-2 py-0.5 rounded-md">
            <span className={`w-1.5 h-1.5 rounded-full ${priority.dot}`} />
            {priority.label}
          </span>
          <span className="text-[10px] font-medium text-steel-500 bg-steel-50 px-2 py-0.5 rounded-md">
            {CATEGORY_LABELS[ticket.category] || ticket.category}
          </span>
        </div>

        <div className="flex items-center justify-between mt-3 pt-2.5 border-t border-steel-100">
          <span className="text-[10px] text-steel-500 flex items-center gap-1">
            <User className="w-3 h-3" />
            {ticket.submitted_by}
          </span>
          <span className="text-[10px] text-steel-400 flex items-center gap-1">
            <Clock className="w-3 h-3" />
            {timeAgo(ticket.created_at)}
          </span>
        </div>
      </div>
    </div>
  );
};

const TicketDetailPanel: React.FC<{
  ticket: TicketWithAgency;
  onBack: () => void;
  onStatusChange: (id: string, status: CrmTicket['status']) => void;
}> = ({ ticket, onBack, onStatusChange }) => {
  const [messages, setMessages] = useState<CrmTicketMessage[]>([]);
  const [loadingMessages, setLoadingMessages] = useState(true);
  const [reply, setReply] = useState('');
  const [sending, setSending] = useState(false);
  const [currentStatus, setCurrentStatus] = useState(ticket.status);

  const loadMessages = useCallback(async () => {
    const { data } = await supabase
      .from('crm_ticket_messages')
      .select('*')
      .eq('ticket_id', ticket.id)
      .order('created_at', { ascending: true });
    setMessages(data || []);
    setLoadingMessages(false);
  }, [ticket.id]);

  useEffect(() => { loadMessages(); }, [loadMessages]);

  const handleReply = async () => {
    if (!reply.trim()) return;
    setSending(true);
    await supabase.from('crm_ticket_messages').insert({
      ticket_id: ticket.id,
      sender_type: 'admin',
      sender_name: 'CRM Team',
      message: reply.trim(),
    });
    await supabase.from('crm_tickets').update({ updated_at: new Date().toISOString() }).eq('id', ticket.id);
    setReply('');
    setSending(false);
    loadMessages();
  };

  const handleStatusUpdate = async (status: CrmTicket['status']) => {
    setCurrentStatus(status);
    onStatusChange(ticket.id, status);
  };

  const priority = PRIORITY_CONFIG[ticket.priority] || PRIORITY_CONFIG.normal;

  return (
    <div className="space-y-4">
      <button
        onClick={onBack}
        className="flex items-center gap-1.5 text-sm font-medium text-steel-600 hover:text-navy-700 transition-colors group"
      >
        <ArrowLeft className="w-4 h-4 group-hover:-translate-x-0.5 transition-transform" />
        Back to board
      </button>

      <div className="bg-white rounded-2xl border border-steel-200 shadow-sm overflow-hidden">
        <div className="px-6 py-5 border-b border-steel-100">
          <div className="flex items-start justify-between gap-4">
            <div>
              <h2 className="text-lg font-bold text-steel-900">{ticket.subject}</h2>
              <div className="flex items-center gap-3 mt-2 text-sm text-steel-500">
                <span className="flex items-center gap-1">
                  <Building2 className="w-3.5 h-3.5" />
                  {ticket.agency_name}
                </span>
                <span className="flex items-center gap-1">
                  <User className="w-3.5 h-3.5" />
                  {ticket.submitted_by}
                </span>
                <span className="flex items-center gap-1">
                  <Clock className="w-3.5 h-3.5" />
                  {new Date(ticket.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric', hour: 'numeric', minute: '2-digit' })}
                </span>
              </div>
            </div>
            <div className="flex items-center gap-2 shrink-0">
              <select
                value={currentStatus}
                onChange={e => handleStatusUpdate(e.target.value as CrmTicket['status'])}
                className="text-xs font-medium px-3 py-1.5 rounded-lg border border-steel-200 bg-steel-50 text-steel-700 focus:outline-none focus:ring-2 focus:ring-navy-300"
              >
                <option value="open">Open</option>
                <option value="in-progress">In Progress</option>
                <option value="resolved">Resolved</option>
                <option value="closed">Closed</option>
              </select>
            </div>
          </div>

          <div className="flex items-center gap-2 mt-3">
            <span className="inline-flex items-center gap-1 text-xs font-medium text-steel-600 bg-steel-100 px-2 py-1 rounded">
              <span className={`w-2 h-2 rounded-full ${priority.dot}`} />
              {priority.label} Priority
            </span>
            <span className="inline-flex items-center gap-1 text-xs font-medium text-steel-600 bg-steel-100 px-2 py-1 rounded">
              <Tag className="w-3 h-3" />
              {CATEGORY_LABELS[ticket.category] || ticket.category}
            </span>
          </div>
        </div>

        {/* Description */}
        <div className="px-6 py-4 border-b border-steel-100 bg-steel-25">
          <p className="text-sm text-steel-700 whitespace-pre-wrap">{ticket.description}</p>
        </div>

        {/* Messages Thread */}
        <div className="px-6 py-4 border-b border-steel-100 max-h-[400px] overflow-y-auto space-y-4">
          {loadingMessages ? (
            <div className="flex items-center justify-center py-8">
              <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-navy-600" />
            </div>
          ) : messages.length === 0 ? (
            <div className="text-center py-8">
              <MessageSquareText className="w-8 h-8 text-steel-300 mx-auto mb-2" />
              <p className="text-sm text-steel-400">No replies yet</p>
            </div>
          ) : (
            messages.map(msg => (
              <div key={msg.id} className={`flex ${msg.sender_type === 'admin' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] rounded-xl px-4 py-3 ${
                  msg.sender_type === 'admin'
                    ? 'bg-navy-600 text-white'
                    : 'bg-steel-100 text-steel-800'
                }`}>
                  <div className="flex items-center gap-2 mb-1">
                    <span className={`text-[10px] font-semibold ${msg.sender_type === 'admin' ? 'text-navy-200' : 'text-steel-500'}`}>
                      {msg.sender_name}
                    </span>
                    <span className={`text-[10px] ${msg.sender_type === 'admin' ? 'text-navy-300' : 'text-steel-400'}`}>
                      {timeAgo(msg.created_at)}
                    </span>
                  </div>
                  <p className="text-sm whitespace-pre-wrap">{msg.message}</p>
                </div>
              </div>
            ))
          )}
        </div>

        {/* Reply Input */}
        <div className="px-6 py-4">
          <div className="flex items-end gap-3">
            <textarea
              value={reply}
              onChange={e => setReply(e.target.value)}
              placeholder="Type a reply as CRM Team..."
              rows={2}
              className="flex-1 px-4 py-2.5 text-sm border border-steel-200 rounded-lg resize-none focus:outline-none focus:ring-2 focus:ring-navy-300 focus:border-navy-400"
              onKeyDown={e => { if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) handleReply(); }}
            />
            <button
              onClick={handleReply}
              disabled={!reply.trim() || sending}
              className="px-4 py-2.5 bg-navy-600 text-white rounded-lg text-sm font-medium hover:bg-navy-700 transition-colors disabled:opacity-50 flex items-center gap-2"
            >
              <Send className="w-4 h-4" />
              {sending ? 'Sending...' : 'Reply'}
            </button>
          </div>
          <p className="text-[10px] text-steel-400 mt-1.5">Press Cmd+Enter to send</p>
        </div>
      </div>
    </div>
  );
};

src/pages/crm/TaskboardOnboardingTab.tsx:
import React, { useState, useEffect } from 'react';
import { Building2, AlertTriangle, ChevronRight } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import type { CrmAgency } from '../../lib/supabase';
import { AgencyOnboardingView } from './AgencyOnboardingView';

const ONBOARDING_STEPS = [
  { key: 'pending_csr_assignment', label: 'CSR Assignment', short: '1' },
  { key: 'awaiting_agency_phone', label: 'Phone & Setup', short: '2' },
  { key: 'awaiting_roster_upload', label: 'Roster Upload', short: '3' },
  { key: 'awaiting_dba_upload', label: 'DBA Upload', short: '4' },
  { key: 'onboarding_complete', label: 'Complete', short: '5' },
] as const;

export const TaskboardOnboardingTab: React.FC = () => {
  const [agencies, setAgencies] = useState<CrmAgency[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedAgency, setSelectedAgency] = useState<CrmAgency | null>(null);
  const [pendingActionCount, setPendingActionCount] = useState(0);

  const load = async () => {
    const [agencyRes, notifRes] = await Promise.all([
      supabase
        .from('crm_agencies')
        .select('*')
        .neq('onboarding_status', 'onboarding_complete')
        .eq('is_active', true)
        .order('date_added', { ascending: false }),
      supabase
        .from('crm_notifications')
        .select('id')
        .eq('is_read', false)
        .in('type', ['roster_uploaded', 'dba_uploaded']),
    ]);
    setAgencies(agencyRes.data || []);
    setPendingActionCount((notifRes.data || []).length);
    setLoading(false);
  };

  useEffect(() => { load(); }, []);

  const handleAgencyUpdated = (updated: CrmAgency) => {
    setAgencies((prev) => prev.map((a) => a.id === updated.id ? updated : a));
    setSelectedAgency(updated);
  };

  if (selectedAgency) {
    return (
      <AgencyOnboardingView
        agency={selectedAgency}
        onBack={() => { setSelectedAgency(null); load(); }}
        onAgencyUpdated={handleAgencyUpdated}
      />
    );
  }

  if (loading) {
    return (
      <div className="space-y-4">
        <div className="h-16 bg-white rounded-2xl border border-steel-200 animate-pulse" />
        {[...Array(3)].map((_, i) => <div key={i} className="h-28 bg-white rounded-2xl border border-steel-200 animate-pulse" />)}
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {pendingActionCount > 0 && (
        <div className="flex items-center gap-3 p-4 bg-amber-50 border border-amber-200 rounded-2xl shadow-sm">
          <div className="w-9 h-9 rounded-xl bg-amber-100 flex items-center justify-center flex-shrink-0">
            <AlertTriangle className="w-5 h-5 text-amber-600" />
          </div>
          <div className="flex-1">
            <p className="text-sm font-medium text-amber-800">
              {pendingActionCount} pending confirmation{pendingActionCount !== 1 ? 's' : ''} require your attention
            </p>
            <p className="text-xs text-amber-600 mt-0.5">Roster or DBA uploads awaiting review</p>
          </div>
        </div>
      )}

      {agencies.length === 0 ? (
        <div className="bg-white rounded-2xl border border-steel-200 p-12 text-center shadow-sm">
          <div className="w-14 h-14 rounded-2xl bg-steel-100 flex items-center justify-center mx-auto mb-4">
            <Building2 className="w-7 h-7 text-steel-400" />
          </div>
          <p className="text-sm font-medium text-steel-600">No agencies currently in onboarding</p>
          <p className="text-xs text-steel-400 mt-1">New agencies will appear here when they begin onboarding</p>
        </div>
      ) : (
        <div>
          <div className="flex items-center justify-between mb-4">
            <h4 className="text-sm font-semibold text-steel-700">
              Agencies In Onboarding
            </h4>
            <span className="text-xs font-bold text-navy-600 bg-navy-50 px-2.5 py-1 rounded-full">
              {agencies.length}
            </span>
          </div>
          <div className="space-y-3">
            {agencies.map((agency) => {
              const currentStepIdx = ONBOARDING_STEPS.findIndex(
                (s) => s.key === agency.onboarding_status
              );
              const progressPercent = Math.round((currentStepIdx / (ONBOARDING_STEPS.length - 1)) * 100);

              return (
                <button
                  key={agency.id}
                  onClick={() => setSelectedAgency(agency)}
                  className="w-full bg-white rounded-2xl border border-steel-200 p-5 text-left hover:border-navy-300 hover:shadow-md transition-all duration-200 group shadow-sm"
                >
                  {/* Progress bar at top */}
                  <div className="h-1 bg-steel-100 rounded-full mb-4 overflow-hidden">
                    <div
                      className="h-full bg-gradient-to-r from-navy-500 to-emerald-500 rounded-full transition-all duration-500"
                      style={{ width: `${progressPercent}%` }}
                    />
                  </div>

                  <div className="flex items-center justify-between mb-4">
                    <div className="flex items-center gap-3">
                      <div className="w-9 h-9 rounded-xl bg-navy-50 border border-navy-100 flex items-center justify-center">
                        <Building2 className="w-4.5 h-4.5 text-navy-600" />
                      </div>
                      <div>
                        <h4 className="font-semibold text-steel-900 group-hover:text-navy-800 transition-colors">{agency.name}</h4>
                        <p className="text-[11px] text-steel-500 mt-0.5">
                          Added {new Date(agency.date_added).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
                        </p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      {agency.assigned_csr && (
                        <span className="text-[11px] font-medium text-steel-600 bg-steel-100 px-2.5 py-1 rounded-lg">
                          CSR: {agency.assigned_csr}
                        </span>
                      )}
                      <ChevronRight className="w-4 h-4 text-steel-400 group-hover:text-navy-600 group-hover:translate-x-0.5 transition-all" />
                    </div>
                  </div>

                  <div className="flex items-center gap-1">
                    {ONBOARDING_STEPS.slice(0, -1).map((step, idx) => {
                      const isActive = idx === currentStepIdx;
                      const isCompleted = idx < currentStepIdx;

                      return (
                        <React.Fragment key={step.key}>
                          <div className="flex items-center gap-2 flex-1">
                            <div
                              className={`w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0 transition-all ${
                                isCompleted
                                  ? 'bg-emerald-500 text-white shadow-sm'
                                  : isActive
                                  ? 'bg-navy-600 text-white ring-2 ring-navy-500/20 shadow-sm'
                                  : 'bg-steel-200 text-steel-500'
                              }`}
                            >
                              {step.short}
                            </div>
                            <span
                              className={`text-[11px] font-medium whitespace-nowrap ${
                                isActive ? 'text-navy-600' : isCompleted ? 'text-emerald-600' : 'text-steel-400'
                              }`}
                            >
                              {step.label}
                            </span>
                          </div>
                          {idx < ONBOARDING_STEPS.length - 2 && (
                            <div className={`h-0.5 flex-1 min-w-[16px] rounded-full ${
                              idx < currentStepIdx ? 'bg-emerald-400' : 'bg-steel-200'
                            }`} />
                          )}
                        </React.Fragment>
                      );
                    })}
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      )}
    </div>
  );
};

src/pages/crm/TemplateManagementTab.tsx:
import React, { useState, useEffect, useRef } from 'react';
import { Upload, Download, Trash2, FileSpreadsheet, Plus, X } from 'lucide-react';
import { supabase } from '../../lib/supabase';
import type { CrmTemplate } from '../../lib/supabase';
import { parseCSV } from '../../lib/csvParser';
import { ConfirmationModal } from '../../components/ConfirmationModal';

const escapeCSVField = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`;
  }
  return value;
};

export const TemplateManagementTab: React.FC = () => {
  const [templates, setTemplates] = useState<CrmTemplate[]>([]);
  const [loading, setLoading] = useState(true);
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [deleteTarget, setDeleteTarget] = useState<CrmTemplate | null>(null);
  const [deleting, setDeleting] = useState(false);

  const loadTemplates = async () => {
    setLoading(true);
    const { data } = await supabase
      .from('crm_templates')
      .select('*')
      .order('created_at', { ascending: false });
    setTemplates(data || []);
    setLoading(false);
  };

  useEffect(() => { loadTemplates(); }, []);

  const handleDownload = (template: CrmTemplate) => {
    const csvHeader = template.headers.map(escapeCSVField).join(',');
    const csvRows = (template.sample_rows || []).map((row) =>
      template.headers.map((h) => escapeCSVField(row[h] || '')).join(',')
    );
    const csvContent = [csvHeader, ...csvRows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = template.file_name || `${template.name}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleDelete = async () => {
    if (!deleteTarget) return;
    setDeleting(true);
    await supabase.from('crm_templates').delete().eq('id', deleteTarget.id);
    setDeleting(false);
    setDeleteTarget(null);
    await loadTemplates();
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[300px]">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-navy-600" />
      </div>
    );
  }

  return (
    <>
      <div className="flex items-center justify-between mb-5">
        <div>
          <p className="text-sm text-gray-500">
            Upload CSV templates that agencies can download during onboarding
          </p>
        </div>
        <button
          onClick={() => setShowUploadModal(true)}
          className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-white bg-navy-600 rounded-lg hover:bg-navy-700 transition-colors"
        >
          <Plus className="w-4 h-4" />
          Upload Template
        </button>
      </div>

      {templates.length === 0 ? (
        <div className="bg-white rounded-xl border border-gray-200 p-12 text-center">
          <FileSpreadsheet className="w-12 h-12 text-gray-300 mx-auto mb-3" />
          <p className="text-gray-500">No templates uploaded yet</p>
          <p className="text-sm text-gray-400 mt-1">
            Upload a CSV file to create a downloadable template for agencies
          </p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {templates.map((template) => (
            <TemplateCard
              key={template.id}
              template={template}
              onDownload={() => handleDownload(template)}
              onDelete={() => setDeleteTarget(template)}
            />
          ))}
        </div>
      )}

      {showUploadModal && (
        <UploadTemplateModal
          onClose={() => setShowUploadModal(false)}
          onSuccess={() => { setShowUploadModal(false); loadTemplates(); }}
        />
      )}

      {deleteTarget && (
        <ConfirmationModal
          title="Delete Template"
          message={
            <p>
              Are you sure you want to delete the template{' '}
              <span className="font-semibold">"{deleteTarget.name}"</span>?
              This cannot be undone.
            </p>
          }
          confirmLabel="Delete"
          confirmColor="bg-red-600 hover:bg-red-700"
          onConfirm={handleDelete}
          onCancel={() => setDeleteTarget(null)}
          loading={deleting}
        />
      )}
    </>
  );
};

const TemplateCard: React.FC<{
  template: CrmTemplate;
  onDownload: () => void;
  onDelete: () => void;
}> = ({ template, onDownload, onDelete }) => (
  <div className="bg-white rounded-xl border border-gray-200 p-5 hover:border-gray-300 transition-colors">
    <div className="flex items-start justify-between mb-3">
      <div className="flex items-center gap-3">
        <div className="w-10 h-10 rounded-lg bg-blue-50 flex items-center justify-center flex-shrink-0">
          <FileSpreadsheet className="w-5 h-5 text-navy-600" />
        </div>
        <div>
          <h4 className="font-semibold text-gray-900 text-sm">{template.name}</h4>
          {template.description && (
            <p className="text-xs text-gray-500 mt-0.5">{template.description}</p>
          )}
        </div>
      </div>
    </div>

    <div className="mb-4">
      <p className="text-xs font-medium text-gray-500 mb-1.5">Columns ({template.headers.length})</p>
      <div className="flex flex-wrap gap-1">
        {template.headers.slice(0, 6).map((h) => (
          <span key={h} className="inline-flex px-2 py-0.5 bg-gray-100 text-gray-600 rounded text-xs">
            {h}
          </span>
        ))}
        {template.headers.length > 6 && (
          <span className="inline-flex px-2 py-0.5 bg-gray-100 text-gray-400 rounded text-xs">
            +{template.headers.length - 6} more
          </span>
        )}
      </div>
    </div>

    <div className="flex items-center justify-between pt-3 border-t border-gray-100">
      <p className="text-xs text-gray-400">
        {new Date(template.created_at).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}
      </p>
      <div className="flex items-center gap-1">
        <button
          onClick={onDownload}
          className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium text-navy-600 bg-blue-50 rounded-lg hover:bg-blue-100 transition-colors"
        >
          <Download className="w-3.5 h-3.5" />
          Download
        </button>
        <button
          onClick={onDelete}
          className="p-1.5 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
        >
          <Trash2 className="w-3.5 h-3.5" />
        </button>
      </div>
    </div>
  </div>
);

const UploadTemplateModal: React.FC<{
  onClose: () => void;
  onSuccess: () => void;
}> = ({ onClose, onSuccess }) => {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [parsedHeaders, setParsedHeaders] = useState<string[]>([]);
  const [parsedSampleRows, setParsedSampleRows] = useState<Record<string, string>[]>([]);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');
  const fileRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (!f) return;
    setFile(f);
    setError('');

    const text = await f.text();
    const { headers, rows } = parseCSV(text);
    setParsedHeaders(headers);
    setParsedSampleRows(rows.slice(0, 3));

    if (!name) {
      setName(f.name.replace(/\.csv$/i, '').replace(/[_-]/g, ' '));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!name.trim()) {
      setError('Template name is required.');
      return;
    }
    if (parsedHeaders.length === 0) {
      setError('Please upload a valid CSV file.');
      return;
    }

    setSubmitting(true);

    const { error: insertError } = await supabase
      .from('crm_templates')
      .insert({
        name: name.trim(),
        description: description.trim(),
        file_name: file?.name || `${name.trim()}.csv`,
        headers: parsedHeaders,
        sample_rows: parsedSampleRows,
      });

    if (insertError) {
      if (insertError.code === '23505') {
        setError('A template with this name already exists.');
      } else {
        setError('Failed to save template. Please try again.');
      }
      setSubmitting(false);
      return;
    }

    setSubmitting(false);
    onSuccess();
  };

  return (
    <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-xl shadow-xl max-w-lg w-full max-h-[90vh] overflow-y-auto">
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-200">
          <h2 className="text-lg font-bold text-navy-600">Upload Template</h2>
          <button onClick={onClose} className="p-1 hover:bg-gray-100 rounded transition-colors">
            <X className="w-5 h-5 text-gray-400" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="px-6 py-5 space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">CSV File</label>
            <input
              ref={fileRef}
              type="file"
              accept=".csv"
              onChange={handleFileChange}
              className="hidden"
            />
            {!file ? (
              <button
                type="button"
                onClick={() => fileRef.current?.click()}
                className="w-full flex flex-col items-center justify-center py-8 border-2 border-dashed border-gray-300 rounded-lg hover:border-navy-600/40 hover:bg-blue-50/30 transition-colors cursor-pointer"
              >
                <Upload className="w-8 h-8 text-gray-400 mb-2" />
                <p className="text-sm font-medium text-gray-600">Click to select a CSV file</p>
                <p className="text-xs text-gray-400 mt-1">The headers will be used as template columns</p>
              </button>
            ) : (
              <div className="flex items-center gap-3 p-3 bg-blue-50 rounded-lg border border-blue-200">
                <FileSpreadsheet className="w-5 h-5 text-navy-600" />
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-gray-900 truncate">{file.name}</p>
                  <p className="text-xs text-gray-500">{parsedHeaders.length} columns detected</p>
                </div>
                <button
                  type="button"
                  onClick={() => { setFile(null); setParsedHeaders([]); setParsedSampleRows([]); if (fileRef.current) fileRef.current.value = ''; }}
                  className="p-1 hover:bg-blue-100 rounded transition-colors"
                >
                  <X className="w-4 h-4 text-gray-500" />
                </button>
              </div>
            )}
          </div>

          {parsedHeaders.length > 0 && (
            <div>
              <p className="text-xs font-medium text-gray-500 mb-1.5">Detected Columns</p>
              <div className="flex flex-wrap gap-1 max-h-24 overflow-y-auto">
                {parsedHeaders.map((h) => (
                  <span key={h} className="inline-flex px-2 py-0.5 bg-gray-100 text-gray-600 rounded text-xs">
                    {h}
                  </span>
                ))}
              </div>
            </div>
          )}

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Template Name</label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm"
              placeholder="e.g., Agent Roster Template"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Description (optional)</label>
            <input
              type="text"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm"
              placeholder="Brief description of this template"
            />
          </div>

          {error && (
            <p className="text-sm text-red-600 bg-red-50 border border-red-200 rounded-lg px-3 py-2">{error}</p>
          )}

          <div className="flex justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={onClose}
              disabled={submitting}
              className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={submitting || parsedHeaders.length === 0}
              className="px-4 py-2 text-sm font-medium text-white bg-navy-600 rounded-lg hover:bg-navy-700 transition-colors disabled:opacity-50"
            >
              {submitting ? 'Saving...' : 'Save Template'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

