    <div className="min-w-0 flex-1">
      <p className="text-xs text-steel-500">{label}</p>
      {href ? (
        <a href={href} className="text-sm font-medium text-navy-600 hover:underline">
          {value}
        </a>
      ) : (
        <p className="text-sm font-medium text-steel-900">{value}</p>
      )}
    </div>
  </div>
);

