const RosterUpload: React.FC<{ agency: CrmAgency; onRefresh: () => Promise<void> }> = ({
  agency,
  onRefresh,
}) => {
  const [uploadedFile, setUploadedFile] = useState<{ name: string; rowCount: number } | null>(null);
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState('');
  const fileRef = useRef<HTMLInputElement>(null);
  const sentBackReason = agency.roster_sent_back_reason;

  useEffect(() => {
    const load = async () => {
      const { data: existing } = await supabase
        .from('crm_roster_uploads')
        .select('file_name, row_count')
        .eq('agency', agency.name)
        .order('uploaded_at', { ascending: false })
        .limit(1);
      if (existing && existing.length > 0) {
        setUploadedFile({ name: existing[0].file_name, rowCount: existing[0].row_count });
      }
    };
    load();
  }, [agency.name]);

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploading(true);
    setError('');

    try {
      const text = await file.text();
      const { rows: rawRows } = parseCSV(text);
      if (rawRows.length === 0) {
        setError('CSV file appears to be empty or invalid.');
        setUploading(false);
        return;
      }

      const crmNumber = agency.crm_number || '';
      const { headers: canonicalHeaders, rows: normalizedRows } = normalizeRosterRows(rawRows, crmNumber);

      const { data: existing } = await supabase
        .from('crm_roster_uploads')
        .select('id')
        .eq('agency', agency.name);
      if (existing && existing.length > 0) {
        for (const ex of existing) {
          await supabase.from('crm_roster').delete().eq('upload_id', ex.id);
          await supabase.from('crm_roster_uploads').delete().eq('id', ex.id);
        }
      }

      const { data: uploadRecord, error: uploadError } = await supabase
        .from('crm_roster_uploads')
        .insert({ file_name: file.name, row_count: normalizedRows.length, headers: canonicalHeaders, agency: agency.name })
        .select()
        .maybeSingle();

      if (uploadError || !uploadRecord) throw uploadError || new Error('Failed to create upload');

      const BATCH_SIZE = 500;
      for (let i = 0; i < normalizedRows.length; i += BATCH_SIZE) {
        const batch = normalizedRows.slice(i, i + BATCH_SIZE).map((row) => ({
          upload_id: uploadRecord.id,
          row_data: row,
        }));
        await supabase.from('crm_roster').insert(batch);
      }

      await padRosterTo200(uploadRecord.id, canonicalHeaders);

      await supabase.from('crm_notifications').insert({
        agency_id: agency.id,
        type: 'roster_uploaded',
        message: `${agency.name} uploaded their agent roster (${normalizedRows.length} rows) -- action required`,
      });

      if (agency.roster_sent_back_reason) {
        await supabase
          .from('crm_agencies')
          .update({ roster_sent_back_reason: null, updated_at: new Date().toISOString() })
          .eq('id', agency.id);
      }

      setUploadedFile({ name: file.name, rowCount: normalizedRows.length });
    } catch {
      setError('Error uploading CSV. Please check the file and try again.');
    } finally {
      setUploading(false);
      if (fileRef.current) fileRef.current.value = '';
    }
  };

  const downloadRosterTemplate = () => {
    const csvHeader = ROSTER_TEMPLATE_HEADERS.map(escapeField).join(',');
    const blob = new Blob([csvHeader + '\n'], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'agent_roster_template.csv';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="space-y-4">
      {sentBackReason && !uploadedFile && (
        <div className="flex items-start gap-3 p-4 bg-amber-50 rounded-lg border border-amber-200">
          <AlertTriangle className="w-5 h-5 text-amber-600 flex-shrink-0 mt-0.5" />
          <div>
            <p className="text-sm font-semibold text-amber-800">Roster Sent Back</p>
            <p className="text-sm text-amber-700 mt-1">{sentBackReason}</p>
            <p className="text-xs text-amber-600 mt-2">Please address the issue above and re-upload your agent roster.</p>
          </div>
        </div>
      )}

      <button
        onClick={downloadRosterTemplate}
        className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-navy-600 bg-blue-50 rounded-lg hover:bg-blue-100 transition-colors"
      >
        <Download className="w-4 h-4" />
        Download Agent Roster Template
      </button>

      <div>
        <div className="flex items-center gap-2 mb-2">
          <FileSpreadsheet className="w-4 h-4 text-gray-400" />
          <span className="text-xs font-medium text-gray-500 uppercase tracking-wide">
            Upload Your Roster
          </span>
        </div>
        <input ref={fileRef} type="file" accept=".csv" onChange={handleUpload} className="hidden" />
        {!uploadedFile ? (
          <button
            onClick={() => fileRef.current?.click()}
            disabled={uploading}
            className="w-full flex flex-col items-center justify-center py-8 border-2 border-dashed border-gray-300 rounded-lg hover:border-navy-600/40 hover:bg-blue-50/30 transition-colors cursor-pointer disabled:opacity-50"
          >
            <Upload className="w-8 h-8 text-gray-400 mb-2" />
            <p className="text-sm font-medium text-gray-600">
              {uploading ? 'Uploading...' : 'Click to upload agent roster CSV'}
            </p>
          </button>
        ) : (
          <div className="space-y-3">
            <div className="flex items-center gap-3 p-4 bg-emerald-50 rounded-lg border border-emerald-200">
              <CheckCircle2 className="w-5 h-5 text-emerald-600 flex-shrink-0" />
              <div className="flex-1">
                <p className="text-sm font-medium text-gray-900">{uploadedFile.name}</p>
                <p className="text-xs text-gray-500">{uploadedFile.rowCount} rows uploaded</p>
              </div>
              <button
                onClick={() => fileRef.current?.click()}
                disabled={uploading}
                className="text-xs font-medium text-navy-600 hover:underline"
              >
                {uploading ? 'Uploading...' : 'Replace'}
              </button>
            </div>
            <div className="flex items-center gap-2 p-3 bg-amber-50 rounded-lg border border-amber-100">
              <Clock className="w-4 h-4 text-amber-500 flex-shrink-0" />
              <p className="text-xs text-amber-700">
                Awaiting confirmation from our team before the next step unlocks.
              </p>
            </div>
          </div>
        )}
        {error && (
          <div className="flex items-center gap-2 mt-2 text-sm text-red-600">
            <AlertCircle className="w-4 h-4 flex-shrink-0" />
            {error}
          </div>
        )}
      </div>
    </div>
  );
};

const DbaUpload: React.FC<{ agency: CrmAgency; onRefresh: () => Promise<void> }> = ({
  agency,
  onRefresh,
}) => {
  const [templates, setTemplates] = useState<CrmTemplate[]>([]);
  const [uploadedFile, setUploadedFile] = useState<{ name: string; rowCount: number } | null>(null);
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState('');
  const fileRef = useRef<HTMLInputElement>(null);
  const sentBackReason = agency.dba_sent_back_reason;

  useEffect(() => {
    const load = async () => {
      const { data } = await supabase.from('crm_templates').select('*').order('name');
      setTemplates(data || []);

      const { data: existing } = await supabase
        .from('crm_dba_uploads')
        .select('file_name, row_count')
        .eq('agency', agency.name)
        .limit(1);
      if (existing && existing.length > 0) {
        setUploadedFile({ name: existing[0].file_name, rowCount: existing[0].row_count });
      }
    };
    load();
  }, [agency.name]);

  const downloadTemplate = (template: CrmTemplate) => {
    const csvHeader = template.headers.map(escapeField).join(',');
    const blob = new Blob([csvHeader + '\n'], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = template.file_name || `${template.name}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploading(true);
    setError('');

    try {
      const text = await file.text();
      const { headers, rows } = parseCSV(text);
      if (headers.length === 0 || rows.length === 0) {
        setError('CSV file appears to be empty or invalid.');
        setUploading(false);
        return;
      }

      await supabase.from('crm_dba_uploads').delete().eq('agency', agency.name);

      const { data: uploadRecord, error: uploadError } = await supabase
        .from('crm_dba_uploads')
        .insert({ agency: agency.name, file_name: file.name, row_count: rows.length, headers })
        .select()
        .maybeSingle();

      if (uploadError || !uploadRecord) throw uploadError || new Error('Failed to create upload');

      const BATCH_SIZE = 500;
      for (let i = 0; i < rows.length; i += BATCH_SIZE) {
        const batch = rows.slice(i, i + BATCH_SIZE).map((row) => ({
          upload_id: uploadRecord.id,
          row_data: row,
        }));
        await supabase.from('crm_dba_rows').insert(batch);
      }

      await supabase.from('crm_notifications').insert({
        agency_id: agency.id,
        type: 'dba_uploaded',
        message: `${agency.name} uploaded their DBA client roster (${rows.length} rows) -- action required`,
      });

      if (agency.dba_sent_back_reason) {
        await supabase
          .from('crm_agencies')
          .update({ dba_sent_back_reason: null, updated_at: new Date().toISOString() })
          .eq('id', agency.id);
      }

      setUploadedFile({ name: file.name, rowCount: rows.length });
    } catch {
      setError('Error uploading CSV. Please check the file and try again.');
    } finally {
      setUploading(false);
      if (fileRef.current) fileRef.current.value = '';
    }
  };

  const dbaTemplate = templates.find((t) => t.name.toLowerCase().includes('dba'));

  return (
    <div className="space-y-4">
      {sentBackReason && !uploadedFile && (
        <div className="flex items-start gap-3 p-4 bg-amber-50 rounded-lg border border-amber-200">
          <AlertTriangle className="w-5 h-5 text-amber-600 flex-shrink-0 mt-0.5" />
          <div>
            <p className="text-sm font-semibold text-amber-800">DBA Roster Sent Back</p>
            <p className="text-sm text-amber-700 mt-1">{sentBackReason}</p>
            <p className="text-xs text-amber-600 mt-2">Please address the issue above and re-upload your DBA client roster.</p>
          </div>
        </div>
      )}

      {dbaTemplate && (
        <button
          onClick={() => downloadTemplate(dbaTemplate)}
          className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-navy-600 bg-blue-50 rounded-lg hover:bg-blue-100 transition-colors"
        >
          <Download className="w-4 h-4" />
          Download DBA Client Roster Template
        </button>
      )}

      <div>
        <div className="flex items-center gap-2 mb-2">
          <FileSpreadsheet className="w-4 h-4 text-gray-400" />
          <span className="text-xs font-medium text-gray-500 uppercase tracking-wide">
            Upload Your DBA Roster
          </span>
        </div>
        <input ref={fileRef} type="file" accept=".csv" onChange={handleUpload} className="hidden" />
        {!uploadedFile ? (
          <button
            onClick={() => fileRef.current?.click()}
            disabled={uploading}
            className="w-full flex flex-col items-center justify-center py-8 border-2 border-dashed border-gray-300 rounded-lg hover:border-navy-600/40 hover:bg-blue-50/30 transition-colors cursor-pointer disabled:opacity-50"
          >
            <Upload className="w-8 h-8 text-gray-400 mb-2" />
            <p className="text-sm font-medium text-gray-600">
              {uploading ? 'Uploading...' : 'Click to upload DBA client roster CSV'}
            </p>
          </button>
        ) : (
          <div className="space-y-3">
            <div className="flex items-center gap-3 p-4 bg-emerald-50 rounded-lg border border-emerald-200">
              <CheckCircle2 className="w-5 h-5 text-emerald-600 flex-shrink-0" />
              <div className="flex-1">
                <p className="text-sm font-medium text-gray-900">{uploadedFile.name}</p>
                <p className="text-xs text-gray-500">{uploadedFile.rowCount} rows uploaded</p>
              </div>
              <button
                onClick={() => fileRef.current?.click()}
                disabled={uploading}
                className="text-xs font-medium text-navy-600 hover:underline"
              >
                {uploading ? 'Uploading...' : 'Replace'}
              </button>
            </div>
            <div className="flex items-center gap-2 p-3 bg-amber-50 rounded-lg border border-amber-100">
              <Clock className="w-4 h-4 text-amber-500 flex-shrink-0" />
              <p className="text-xs text-amber-700">
                Awaiting confirmation from our team. Once confirmed, your full portal will be unlocked.
              </p>
            </div>
          </div>
        )}
        {error && (
          <div className="flex items-center gap-2 mt-2 text-sm text-red-600">
            <AlertCircle className="w-4 h-4 flex-shrink-0" />
            {error}
          </div>
        )}
      </div>
    </div>
  );
};

src/pages/portal/PortalTicketsTab.tsx:
import React, { useState, useEffect, useCallback } from 'react';
import {
  MessageSquareText,
  Plus,
  ArrowLeft,
  Clock,
  Send,
  AlertCircle,
  CheckCircle2,
  Loader2,
  Tag,
  User,
  ShieldCheck,
} from 'lucide-react';
import { supabase } from '../../lib/supabase';
import type { CrmAgency, CrmTicket, CrmTicketMessage } from '../../lib/supabase';

interface PortalTicketsTabProps {
  agency: CrmAgency;
  agencyIds: string[];
}

const STATUS_CONFIG: Record<string, { label: string; color: string; icon: React.FC<{ className?: string }> }> = {
  open: { label: 'Open', color: 'bg-blue-100 text-blue-800', icon: AlertCircle },
  'in-progress': { label: 'In Progress', color: 'bg-amber-100 text-amber-800', icon: Loader2 },
  resolved: { label: 'Resolved', color: 'bg-emerald-100 text-emerald-800', icon: CheckCircle2 },
  closed: { label: 'Closed', color: 'bg-gray-100 text-gray-600', icon: CheckCircle2 },
};

const PRIORITY_CONFIG: Record<string, { label: string; color: string }> = {
  low: { label: 'Low', color: 'bg-gray-100 text-gray-600' },
  normal: { label: 'Normal', color: 'bg-blue-50 text-blue-700' },
  high: { label: 'High', color: 'bg-red-50 text-red-700' },
};

const CATEGORY_LABELS: Record<string, string> = {
  'agent-issue': 'Agent Issue',
  'crm-issue': 'CRM Issue',
  billing: 'Billing',
  other: 'Other',
};

function timeAgo(dateStr: string): string {
  const diff = Date.now() - new Date(dateStr).getTime();
  const mins = Math.floor(diff / 60000);
  if (mins < 1) return 'Just now';
  if (mins < 60) return `${mins}m ago`;
  const hrs = Math.floor(mins / 60);
  if (hrs < 24) return `${hrs}h ago`;
  const days = Math.floor(hrs / 24);
  if (days < 7) return `${days}d ago`;
  return new Date(dateStr).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
}

export const PortalTicketsTab: React.FC<PortalTicketsTabProps> = ({ agency, agencyIds }) => {
  const [tickets, setTickets] = useState<CrmTicket[]>([]);
  const [loading, setLoading] = useState(true);
  const [showNewForm, setShowNewForm] = useState(false);
  const [selectedTicket, setSelectedTicket] = useState<CrmTicket | null>(null);
  const [statusFilter, setStatusFilter] = useState('all');

  const loadTickets = useCallback(async () => {
    const { data } = await supabase
      .from('crm_tickets')
      .select('*')
      .in('agency_id', agencyIds)
      .order('created_at', { ascending: false });

    setTickets(data || []);
    setLoading(false);
  }, [agencyIds.join(',')]);

  useEffect(() => { loadTickets(); }, [loadTickets]);

  const filtered = statusFilter === 'all'
    ? tickets
    : tickets.filter((t) => t.status === statusFilter);

  if (selectedTicket) {
    return (
      <TicketDetailView
        ticket={selectedTicket}
        agencyName={agency.name}
        onBack={() => { setSelectedTicket(null); loadTickets(); }}
      />
    );
  }

  if (showNewForm) {
    return (
      <NewTicketForm
        agency={agency}
        onCancel={() => setShowNewForm(false)}
        onSuccess={() => { setShowNewForm(false); loadTickets(); }}
      />
    );
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[300px]">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-navy-600" />
      </div>
    );
  }

  const openCount = tickets.filter((t) => t.status === 'open' || t.status === 'in-progress').length;

  return (
    <div className="space-y-5">
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-3">
        <div>
          <h2 className="text-lg font-bold text-gray-900">Support Tickets</h2>
          <p className="text-sm text-gray-500">
            {openCount > 0 ? `${openCount} open ticket${openCount !== 1 ? 's' : ''}` : 'No open tickets'}
          </p>
        </div>
        <button
          onClick={() => setShowNewForm(true)}
          className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-white bg-navy-600 rounded-lg hover:bg-navy-700 transition-colors"
        >
          <Plus className="w-4 h-4" />
          New Ticket
        </button>
      </div>

      <div className="flex items-center gap-2 bg-white border border-gray-200 rounded-lg p-1 overflow-x-auto">
        {['all', 'open', 'in-progress', 'resolved', 'closed'].map((s) => (
          <button
            key={s}
            onClick={() => setStatusFilter(s)}
            className={`px-3 py-1.5 text-xs font-medium rounded-md transition-colors whitespace-nowrap ${
              statusFilter === s ? 'bg-navy-600 text-white' : 'text-gray-600 hover:bg-gray-100'
            }`}
          >
            {s === 'all' ? `All (${tickets.length})` : `${STATUS_CONFIG[s]?.label || s} (${tickets.filter((t) => t.status === s).length})`}
          </button>
        ))}
      </div>

      {filtered.length === 0 ? (
        <div className="bg-white rounded-xl border border-gray-200 p-12 text-center">
          <MessageSquareText className="w-10 h-10 text-gray-300 mx-auto mb-3" />
          <p className="text-gray-500 text-sm">
            {tickets.length === 0
              ? 'No tickets yet. Create one if you need help.'
              : 'No tickets match this filter.'}
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          {filtered.map((ticket) => {
            const status = STATUS_CONFIG[ticket.status] || STATUS_CONFIG.open;
            const priority = PRIORITY_CONFIG[ticket.priority] || PRIORITY_CONFIG.normal;
            const StatusIcon = status.icon;

            return (
              <button
                key={ticket.id}
                onClick={() => setSelectedTicket(ticket)}
                className="w-full bg-white rounded-xl border border-gray-200 p-5 text-left hover:border-navy-200 hover:shadow-sm transition-all group"
              >
                <div className="flex items-start justify-between gap-3 mb-2">
                  <h3 className="text-sm font-semibold text-gray-900 group-hover:text-navy-600 transition-colors">
                    {ticket.subject}
                  </h3>
                  <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium flex-shrink-0 ${status.color}`}>
                    <StatusIcon className="w-3 h-3" />
                    {status.label}
                  </span>
                </div>
                <p className="text-sm text-gray-500 line-clamp-2 mb-3">{ticket.description}</p>
                <div className="flex items-center gap-3 text-xs text-gray-400">
                  <span className={`inline-flex items-center gap-1 px-1.5 py-0.5 rounded ${priority.color} text-[10px] font-medium`}>
                    {priority.label}
                  </span>
                  <span className="flex items-center gap-1">
                    <Tag className="w-3 h-3" />
                    {CATEGORY_LABELS[ticket.category] || ticket.category}
                  </span>
                  <span className="flex items-center gap-1">
                    <Clock className="w-3 h-3" />
                    {timeAgo(ticket.created_at)}
                  </span>
                  <span>by {ticket.submitted_by}</span>
                </div>
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
};

const NewTicketForm: React.FC<{
  agency: CrmAgency;
  onCancel: () => void;
  onSuccess: () => void;
}> = ({ agency, onCancel, onSuccess }) => {
  const [form, setForm] = useState({
    subject: '',
    description: '',
    category: 'other' as string,
    priority: 'normal' as string,
    submittedBy: '',
  });
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!form.subject.trim() || !form.description.trim() || !form.submittedBy.trim()) {
      setError('Please fill in all required fields.');
      return;
    }

    setSubmitting(true);

    const { error: insertError } = await supabase.from('crm_tickets').insert({
      agency_id: agency.id,
      subject: form.subject.trim(),
      description: form.description.trim(),
      category: form.category,
      priority: form.priority,
      submitted_by: form.submittedBy.trim(),
    });

    if (insertError) {
      setError('Failed to create ticket. Please try again.');
      setSubmitting(false);
      return;
    }

    setSubmitting(false);
    onSuccess();
  };

  return (
    <div className="max-w-2xl">
      <button
        onClick={onCancel}
        className="flex items-center gap-2 text-sm text-gray-600 hover:text-gray-900 mb-4 transition-colors"
      >
        <ArrowLeft className="w-4 h-4" />
        Back to tickets
      </button>

      <div className="bg-white rounded-xl border border-gray-200">
        <div className="px-6 py-4 border-b border-gray-200">
          <h2 className="text-lg font-bold text-gray-900">New Support Ticket</h2>
          <p className="text-sm text-gray-500 mt-0.5">Describe your issue and we'll get back to you.</p>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Your Name <span className="text-red-500">*</span>
            </label>
            <input
              type="text"
              value={form.submittedBy}
              onChange={(e) => setForm((f) => ({ ...f, submittedBy: e.target.value }))}
              className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm"
              placeholder="Your name"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Subject <span className="text-red-500">*</span>
            </label>
            <input
              type="text"
              value={form.subject}
              onChange={(e) => setForm((f) => ({ ...f, subject: e.target.value }))}
              className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm"
              placeholder="Brief description of the issue"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
              <select
                value={form.category}
                onChange={(e) => setForm((f) => ({ ...f, category: e.target.value }))}
                className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm bg-white"
              >
                <option value="agent-issue">Agent Issue</option>
                <option value="crm-issue">CRM Issue</option>
                <option value="billing">Billing</option>
                <option value="other">Other</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Priority</label>
              <select
                value={form.priority}
                onChange={(e) => setForm((f) => ({ ...f, priority: e.target.value }))}
                className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm bg-white"
              >
                <option value="low">Low</option>
                <option value="normal">Normal</option>
                <option value="high">High</option>
              </select>
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">
              Description <span className="text-red-500">*</span>
            </label>
            <textarea
              value={form.description}
              onChange={(e) => setForm((f) => ({ ...f, description: e.target.value }))}
              rows={5}
              className="w-full px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm resize-none"
              placeholder="Provide as much detail as possible..."
            />
          </div>

          {error && (
            <p className="text-sm text-red-600 bg-red-50 border border-red-200 rounded-lg px-3 py-2">{error}</p>
          )}

          <div className="flex justify-end gap-3 pt-2">
            <button
              type="button"
              onClick={onCancel}
              disabled={submitting}
              className="px-4 py-2 text-sm font-medium text-gray-700 bg-white border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={submitting}
              className="px-5 py-2 text-sm font-medium text-white bg-navy-600 rounded-lg hover:bg-navy-700 transition-colors disabled:opacity-50"
            >
              {submitting ? 'Submitting...' : 'Submit Ticket'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

const TicketDetailView: React.FC<{
  ticket: CrmTicket;
  agencyName: string;
  onBack: () => void;
}> = ({ ticket, agencyName, onBack }) => {
  const [messages, setMessages] = useState<CrmTicketMessage[]>([]);
  const [loading, setLoading] = useState(true);
  const [newMessage, setNewMessage] = useState('');
  const [sending, setSending] = useState(false);

  const loadMessages = useCallback(async () => {
    const { data } = await supabase
      .from('crm_ticket_messages')
      .select('*')
      .eq('ticket_id', ticket.id)
      .order('created_at', { ascending: true });

    setMessages(data || []);
    setLoading(false);
  }, [ticket.id]);

  useEffect(() => { loadMessages(); }, [loadMessages]);

  const handleSend = async () => {
    if (!newMessage.trim()) return;
    setSending(true);

    const { error } = await supabase.from('crm_ticket_messages').insert({
      ticket_id: ticket.id,
      sender_type: 'agency',
      sender_name: ticket.submitted_by,
      message: newMessage.trim(),
    });

    if (!error) {
      setNewMessage('');
      loadMessages();
    }
    setSending(false);
  };

  const status = STATUS_CONFIG[ticket.status] || STATUS_CONFIG.open;
  const priority = PRIORITY_CONFIG[ticket.priority] || PRIORITY_CONFIG.normal;
  const StatusIcon = status.icon;
  const canReply = ticket.status === 'open' || ticket.status === 'in-progress';

  return (
    <div className="max-w-3xl">
      <button
        onClick={onBack}
        className="flex items-center gap-2 text-sm text-gray-600 hover:text-gray-900 mb-4 transition-colors"
      >
        <ArrowLeft className="w-4 h-4" />
        Back to tickets
      </button>

      <div className="bg-white rounded-xl border border-gray-200 overflow-hidden">
        <div className="px-6 py-5 border-b border-gray-200">
          <div className="flex items-start justify-between gap-3 mb-3">
            <h2 className="text-lg font-bold text-gray-900">{ticket.subject}</h2>
            <span className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-full text-xs font-medium flex-shrink-0 ${status.color}`}>
              <StatusIcon className="w-3 h-3" />
              {status.label}
            </span>
          </div>
          <div className="flex flex-wrap items-center gap-3 text-xs text-gray-500">
            <span className={`inline-flex items-center gap-1 px-1.5 py-0.5 rounded ${priority.color} text-[10px] font-medium`}>
              {priority.label} Priority
            </span>
            <span className="flex items-center gap-1">
              <Tag className="w-3 h-3" />
              {CATEGORY_LABELS[ticket.category] || ticket.category}
            </span>
            <span className="flex items-center gap-1">
              <Clock className="w-3 h-3" />
              {new Date(ticket.created_at).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric', hour: 'numeric', minute: '2-digit' })}
            </span>
            <span>by {ticket.submitted_by}</span>
          </div>
        </div>

        <div className="px-6 py-4 bg-gray-50 border-b border-gray-200">
          <p className="text-sm text-gray-700 whitespace-pre-wrap">{ticket.description}</p>
        </div>

        <div className="divide-y divide-gray-100">
          {loading ? (
            <div className="flex items-center justify-center py-8">
              <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-navy-600" />
            </div>
          ) : messages.length === 0 ? (
            <div className="px-6 py-8 text-center text-sm text-gray-400">
              No replies yet.
            </div>
          ) : (
            messages.map((msg) => {
              const isAdmin = msg.sender_type === 'admin';
              return (
                <div key={msg.id} className={`px-6 py-4 ${isAdmin ? 'bg-blue-50/40' : ''}`}>
                  <div className="flex items-center gap-2 mb-1.5">
                    <div className={`w-6 h-6 rounded-full flex items-center justify-center ${
                      isAdmin ? 'bg-navy-600/10' : 'bg-gray-100'
                    }`}>
                      {isAdmin
                        ? <ShieldCheck className="w-3 h-3 text-navy-600" />
                        : <User className="w-3 h-3 text-gray-500" />
                      }
                    </div>
                    <span className={`text-sm font-medium ${isAdmin ? 'text-navy-600' : 'text-gray-900'}`}>
                      {msg.sender_name}
                    </span>
                    <span className="text-[10px] text-gray-400 font-medium uppercase">
                      {isAdmin ? 'FYM Support' : agencyName}
                    </span>
                    <span className="text-xs text-gray-400 ml-auto">{timeAgo(msg.created_at)}</span>
                  </div>
                  <p className="text-sm text-gray-700 whitespace-pre-wrap pl-8">{msg.message}</p>
                </div>
              );
            })
          )}
        </div>

        {canReply && (
          <div className="px-6 py-4 border-t border-gray-200 bg-white">
            <div className="flex items-end gap-3">
              <textarea
                value={newMessage}
                onChange={(e) => setNewMessage(e.target.value)}
                rows={2}
                placeholder="Type your reply..."
                className="flex-1 px-4 py-2.5 border border-gray-300 rounded-lg focus:ring-2 focus:ring-navy-500 focus:border-transparent text-sm resize-none"
                onKeyDown={(e) => { if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) handleSend(); }}
              />
              <button
                onClick={handleSend}
                disabled={sending || !newMessage.trim()}
                className="flex items-center gap-2 px-4 py-2.5 text-sm font-medium text-white bg-navy-600 rounded-lg hover:bg-navy-700 transition-colors disabled:opacity-50"
              >
                <Send className="w-4 h-4" />
                {sending ? 'Sending...' : 'Send'}
              </button>
            </div>
          </div>
        )}

        {!canReply && (
          <div className="px-6 py-4 border-t border-gray-200 bg-gray-50 text-center">
            <p className="text-sm text-gray-500">This ticket has been {ticket.status}. No further replies can be added.</p>
          </div>
        )}
      </div>
    </div>
  );
};

